function openMore(){const menu=$('#moreMenu'),backdrop=$('#moreBackdrop');if(menu)menu.hidden=false;if(backdrop)backdrop.hidden=false}
function closeMore(){const menu=$('#moreMenu'),backdrop=$('#moreBackdrop');if(menu)menu.hidden=true;if(backdrop)backdrop.hidden=true}
function goPage(page){closeMore();$$('.page').forEach(p=>p.classList.toggle('active',p.id===`page-${page}`));const morePages=['game','logs','wallet','rewards','quests','challenges','reports','stats','settings','backup','help'];$$('.tab').forEach(t=>t.classList.toggle('active',t.dataset.page===page||(t.id==='moreToggle'&&morePages.includes(page))));renderAll();scrollTo({top:0,behavior:'smooth'})}
function stableFlexKey(t){const raw=state.missions.flex.periodKeys?.[t.id]||periodKey(t.frequencyRule);const key=String(raw||'');return key.startsWith(`${t.id}:`)?key:`${t.id}:${key}`}
function pickReplacement(list,oldId,pool,seedPrefix,opts={}){const usedIds=new Set(list);usedIds.delete(oldId);const existing=list.filter(id=>id!==oldId).map(id=>pool.find(x=>x.id===id)).filter(Boolean);const usedSig=new Set(existing.map(taskSignature));const existingLong=existing.filter(t=>t.longTerm).length;for(const row of pool.map(x=>({task:x,score:hash(seedPrefix+x.id)})).sort((a,b)=>a.score-b.score)){if(usedIds.has(row.task.id))continue;if(opts.maxLongTerm!=null&&row.task.longTerm&&existingLong>=opts.maxLongTerm)continue;const sig=taskSignature(row.task);if(usedSig.has(sig))continue;return row.task.id}return oldId}function hash(s){let h=2166136261;for(let i=0;i<s.length;i++){h^=s.charCodeAt(i);h=Math.imul(h,16777619)}return h>>>0}
function completeSecretToday(id){
  const row=(state.secretTasks||[]).find(x=>x.id===id&&!x.deletedAt);if(!row)return toast('找不到秘密任務');
  if(row.status==='completed')return toast('秘密任務已完成');
  const t=dailyMissionPool.find(x=>x.id===row.taskId)||row;
  const title=t.title||row.title||'秘密任務';
  row.status='completed';row.completedAt=nowIso();row.revealDate=row.revealDate||addDaysKey(todayKey(),1);row.revealed=false;row.revealedAt=null;row.visibleToPartnerAfterComplete=true;row.partnerCanSeeTitle=false;row.partnerCanSeeContent=false;row.publicTitle=parseTaskTitleMain(title);row.publicDescription=parseTaskContent(title)||t.description||row.description||'';row.updatedAt=nowIso();
  addLog({...t,id:row.id,title,points:Number(t.points||5),pack:'secret',category:t.category||'秘密'}, {type:'secretMission',periodKey:todayKey(),periodLabel:'今日',points:Number(t.points||5)});
  addPoints(3,'secretCouple','完成秘密任務雙人點數',row.id);
  try{addCouplePoints(5,'secretMission','完成秘密任務',row.id)}catch{}
  try{applyBossDamage(15,'secretTask',`秘密任務攻擊 Boss：${title}`,{taskId:row.id})}catch{}
  state.relationshipLogs.unshift(withMeta({id:uid('rel'),date:todayKey(),title,description:t.description||row.description,secret:true,revealed:false,revealDate:row.revealDate,intimacy:5,harmony:0},'relationship',state));
  checkDailyPackRewards('secret');updateCoupleStats();saveState();renderAll();toast('秘密任務已完成，明天會向對方揭曉名稱與內容')
}
function secretHelp(id){const row=(state.secretTasks||[]).find(x=>x.id===id);const t=dailyMissionPool.find(x=>x.id===row?.taskId)||row;if(!t)return;alert(`秘密任務：${t.title}\n\n${t.description||''}\n\n規則：一天型任務，不可換、不可跳過、不可補救。完成前對方只知道你有秘密任務；完成後可揭曉名稱與內容。`)}
function completeDaily(id){ensureMissions();const t=dailyMissionPool.find(x=>x.id===id);if(!t)return;if(!addLog(t,{type:'dailyMission',periodKey:todayKey(),periodLabel:'今日'}))return toast('今天已完成這個任務');state.missions.daily.completed[id]=true;setMissionTaskStatus('daily',id,'completed',{completedAt:new Date().toISOString()});checkStreakRewards();contributeCoupleProgress(1,'dailyMission',`完成任務：${t.title}`,{relatedId:t.id});updateCoupleStats();saveState();renderAll();toast(`完成：${t.title}`)}
function undoDaily(id){if(!removeTodayLog(id))return toast('目前沒有可恢復的完成紀錄');delete state.missions.daily.completed[id];setMissionTaskStatus('daily',id,'active',{completedAt:''});saveState();renderAll();toast('已恢復上一步')}
function checkDailyPackRewards(pack){state.missions.daily.packRewards=state.missions.daily.packRewards||{};if(!pack||state.missions.daily.packRewards[pack])return;let total=0,done=0;if(pack==='secret'){const rows=(state.secretTasks||[]).filter(x=>x.date===todayKey()&&!x.deletedAt);total=rows.length;done=rows.filter(x=>x.status==='completed'||x.completedAt).length;}else{const tasks=state.habits.filter(h=>!h.deletedAt&&h.taskSource!=='system'&&(h.pack||h.type||'side')===pack);total=tasks.length;done=tasks.filter(t=>state.logs[`${todayKey()}:${t.id}`]).length;}if(!total||done<total)return;state.missions.daily.packRewards[pack]=new Date().toISOString();if(pack==='main'){adjustItem('抽獎券',1);grantItem('轉盤機會',1,'spin');addGameLog('dailyPackReward','完成主線任務包：抽獎券 +1、轉盤機會 +1',{pack,items:['抽獎券','轉盤機會']});toast('完成主線任務包，獲得抽獎券 +1、轉盤機會 +1');}else if(pack==='secret'){adjustItem('木寶箱',1);grantItem('轉盤機會',1,'spin');addGameLog('dailyPackReward','完成秘密任務包：木寶箱 +1、轉盤機會 +1',{pack,items:['木寶箱','轉盤機會']});toast('完成秘密任務包，獲得木寶箱 +1、轉盤機會 +1');}else{addPoints(5,'dailyPackReward',`完成${pack}任務包額外獎勵`,pack);grantItem('轉盤機會',1,'spin');addGameLog('dailyPackReward',`完成${pack}任務包：+5 點、轉盤機會 +1`,{pack,points:5,item:'轉盤機會'});toast('完成任務包，獲得額外 +5 點與轉盤機會 +1');}}

function swapDaily(slot){ensureMissions();slot=Number(slot);if(state.missions.daily.swapped[String(slot)])return toast('今日已換過');const oldId=state.missions.daily.ids[slot];state.missions.daily.swapped[String(slot)]=true;const next=pickReplacement(state.missions.daily.ids,oldId,dailyMissionPool,`dailySwap:${todayKey()}:${slot}:`);if(next){state.missions.daily.ids[slot]=next;recordSwap('daily',slot,oldId,next);state.taskSwapLogs.unshift(withMeta({id:uid('swap'),date:todayKey(),taskType:'dailySpecial',slot,fromTaskId:oldId,toTaskId:next,free:true},'taskSwapLog',state));}saveState();renderAll();toast('已換下一張')}
function completeFlex(id){ensureMissions();const t=flexMissionPool.find(x=>x.id===id);if(!t)return;const meta=state.missions.flex.periodMeta?.[t.id]||periodMeta(t.frequencyRule);const key=stableFlexKey(t);const done=Number(state.missions.flex.progress[key]||0);if(done>=t.target)return toast('本期已完成');if(state.missions.flex.todayDone[id])return toast('今天已完成這張');state.missions.flex.progress[key]=done+1;state.missions.flex.todayDone[id]=true;setMissionTaskStatus('flex',id,state.missions.flex.progress[key]>=t.target?'completed':'in_progress',{progress:state.missions.flex.progress[key],periodKey:meta.periodKey,periodStart:meta.periodStart,periodEnd:meta.periodEnd,completedAt:state.missions.flex.progress[key]>=t.target?new Date().toISOString():''});addLog(t,{type:'flexMission',periodKey:meta.periodKey,periodLabel:periodLabel(t.frequencyRule),frequencyDescription:frequencyDescription(t.frequencyRule)});if(state.missions.flex.progress[key]>=t.target){state.missions.flex.statuses=state.missions.flex.statuses||{};state.missions.flex.statuses[t.id]={status:'completedWaitingRefresh',completedDate:todayKey(),updatedAt:nowIso()};addPoints(10,'flexBonus',`達成本期彈性任務：${t.title}`,t.id);grantItem('任務券',1,'ticket')}checkStreakRewards();contributeCoupleProgress(1,'flexMission',`完成彈性任務：${t.title}`,{relatedId:t.id});updateCoupleStats();saveState();renderAll();toast(`本期進度 ${state.missions.flex.progress[key]}/${t.target}`)}
function undoFlex(id){const t=flexMissionPool.find(x=>x.id===id);if(!t)return;const key=stableFlexKey(t);if(!state.missions.flex.todayDone[id]&&!removeTodayLog(id))return toast('目前沒有可恢復的完成紀錄');removeTodayLog(id);state.missions.flex.todayDone[id]=false;state.missions.flex.progress[key]=Math.max(0,Number(state.missions.flex.progress[key]||0)-1);if(state.missions.flex.statuses?.[id])state.missions.flex.statuses[id]={status:'active',startedAt:state.missions.flex.statuses[id].startedAt||todayKey(),updatedAt:nowIso()};setMissionTaskStatus('flex',id,state.missions.flex.progress[key]>0?'in_progress':'active',{progress:state.missions.flex.progress[key],completedAt:''});saveState();renderAll();toast('已恢復上一步')}
function swapFlex(slot){ensureMissions();slot=Number(slot);state.missions.flex.swapCounts=state.missions.flex.swapCounts||{};const count=Number(state.missions.flex.swapCounts[String(slot)]||0);if(count>=1&&!consumeItem('換卡券',1))return toast('第二次以上換卡需要換卡券');const oldId=state.missions.flex.ids[slot];state.missions.flex.swapCounts[String(slot)]=count+1;state.missions.flex.swapped[String(slot)]=true;const next=pickReplacement(state.missions.flex.ids,oldId,flexMissionPool,`flexSwap:${todayKey()}:${slot}:${count}:`,{maxLongTerm:1});if(next){state.missions.flex.ids[slot]=next;delete state.missions.flex.periodMeta?.[oldId];delete state.missions.flex.statuses?.[oldId];delete state.missions.flex.todayDone?.[oldId];const nextTask=flexMissionPool.find(x=>x.id===next);const base=Number(nextTask?.frequencyRule?.intervalDays)||7;const total=base+Math.ceil(base/3);const start=todayKey();const end=addDaysKey(start,total-1);const periodKeyNew=`${next}:${start}`;state.missions.flex.periodMeta=state.missions.flex.periodMeta||{};state.missions.flex.periodKeys=state.missions.flex.periodKeys||{};state.missions.flex.statuses=state.missions.flex.statuses||{};state.missions.flex.progress=state.missions.flex.progress||{};state.missions.flex.periodMeta[next]={periodKey:periodKeyNew,periodStart:start,periodEnd:end,totalDays:total,challengeEnd:end,startedAt:start,dayIndex:1,remainingDays:total};state.missions.flex.periodKeys[next]=periodKeyNew;state.missions.flex.statuses[next]={status:'active',startedAt:start,updatedAt:nowIso()};state.missions.flex.progress[periodKeyNew]=0;recordSwap('flex',slot,oldId,next);state.taskSwapLogs.unshift(withMeta({id:uid('swap'),date:todayKey(),taskType:'flex',slot,fromTaskId:oldId,toTaskId:next,free:count===0,usedItem:count>=1?'換卡券':''},'taskSwapLog',state));}saveState();renderAll();toast(count>=1?'已使用換卡券換下一張':'已免費換下一張')}
function partialDaily(id){return toast('今日特殊任務是一日型任務，不支援部分完成')}
function partialFlex(id){const t=flexMissionPool.find(x=>x.id===id);if(!t)return;recordPartial(t,'flexMission');saveState();renderAll()}
function recordPartial(t,type){const raw=prompt('請輸入完成比例 1-100（例如 50 表示完成一半）','50');if(raw===null)return;const ratio=Math.max(0,Math.min(100,Number(raw)||0))/100;if(ratio<=0)return toast('比例需大於 0');const points=Math.max(1,Math.floor((Number(t.points)||0)*ratio));const row=withMeta({id:uid('habitLog'),date:todayKey(),habitId:t.id,taskId:t.id,title:t.title,points,basePoints:t.points,partialRatio:ratio,type,status:'partial',completedAt:nowIso()},'habitLog',state);state.habitLogs.unshift(row);addPoints(points,type,`部分完成 ${Math.round(ratio*100)}%：${t.title}`,t.id);toast(`已記錄部分完成，獲得 ${points} 點`)}
function skipDaily(id){return toast('今日特殊任務不使用跳過券；可換下一張或不完成')}
function addDaysKey(key,n){const d=new Date(key+'T00:00:00');d.setDate(d.getDate()+n);return todayKey(d)}
function skipFlex(id){const t=flexMissionPool.find(x=>x.id===id);if(!t)return;if(!consumeItem('跳過券',1))return toast('需要跳過券');state.missions.flex.todayDone[id]=true;setMissionTaskStatus('flex',id,'skipped',{skippedAt:nowIso()});const row=withMeta({id:uid('habitLog'),date:todayKey(),habitId:t.id,taskId:t.id,title:t.title,points:0,type:'skip',status:'skipped',completedAt:nowIso()},'habitLog',state);state.habitLogs.unshift(row);state.gameLogs.unshift(withMeta({id:uid('game'),date:todayKey(),action:'useSkipTicket',description:`跳過本期彈性任務今日一次：${t.title}`,taskId:id},'gameLog',state));state.itemUseLogs.unshift(withMeta({id:uid('itemUse'),date:todayKey(),item:'跳過券',targetType:'flexTask',targetId:id,description:`免做今天一次，不增加進度：${t.title}`},'itemUseLog',state));saveState();renderAll();toast('已使用跳過券，今天免做一次')}
let pendingUseItemId='';
function itemByIdOrName(id){return state.gameItems.find(x=>x.id===id||x.name===id)||null}
function itemEffectText(it){const name=it?.name||it?.id||'';const m={'抽獎券':'前往翻牌使用，不會在錢包直接扣除。','轉盤機會':'前往轉盤使用，不會在錢包直接扣除。','補救券':'開啟補救流程，選擇昨天未完成的習慣。','加倍卡':'啟用後下一個任務點數 x2。','跳過券':'請在可跳過任務卡上使用。','換卡券':'請在本期彈性任務第二次以上換卡時使用。','商店折價券':'標記為下次兌換可用。','火焰球':'攻擊本週 Boss，造成 30 傷害。','冰凍彈':'攻擊 Boss，並啟用今日任務傷害加成。','破盾券':'對 Boss 破盾並造成傷害。','追加攻擊券':'啟用下一次 Boss 攻擊加倍。','Boss 弱點卡':'啟用本週任務弱點傷害加成。','能量藥水':'恢復挑戰能量或轉成雙人點數。','星光碎片':'集滿 5 個可合成銀寶箱。','地圖換算券':'啟用地圖步數加成，套用到今天 / 下一個主線任務。'};if(String(name).includes('寶箱'))return '開啟寶箱並獲得隨機獎勵。';return m[name]||it?.description||'可使用道具。'}
function itemTargetText(it){const n=it?.name||'';if(['火焰球','冰凍彈','破盾券','追加攻擊券','Boss 弱點卡'].includes(n))return '本週 Boss';if(n==='補救券')return '昨天未完成且允許補救的習慣';if(n==='加倍卡')return '下一個完成的任務';if(n==='地圖換算券')return '今天或下一個主線任務的地圖步數';if(n==='星光碎片')return '合成銀寶箱';if(n.includes('寶箱'))return '立即開箱';if(n==='抽獎券')return '翻牌頁';if(n==='轉盤機會')return '轉盤頁';return '依道具類型選擇'}
function openUseItemModal(id){const it=itemByIdOrName(id);if(!it)return toast('找不到道具');pendingUseItemId=it.id;const modal=$('#itemUseModal'),back=$('#itemUseBackdrop'),title=$('#itemUseTitle'),box=$('#itemUseContent');if(title)title.textContent=`使用道具：${it.name}`;if(box)box.innerHTML=`<article class="item"><div class="item-title">${it.name}</div><div class="item-sub">數量：${it.quantity||0}\n效果：${itemEffectText(it)}\n可使用目標：${itemTargetText(it)}\n用途：${it.usableTarget||''}</div></article>`;if(modal)modal.hidden=false;if(back)back.hidden=false}
function closeUseItemModal(){pendingUseItemId='';const modal=$('#itemUseModal'),back=$('#itemUseBackdrop');if(modal)modal.hidden=true;if(back)back.hidden=true}
function showItemInfo(id){const chest=(state.relationshipChests||[]).find(x=>x.id===id&&!x.deletedAt);const it=itemByIdOrName(id)|| (chest?{name:chest.name||'關係寶箱',quantity:chest.status==='opened'?0:1,description:`來源：${chest.source||'關係互動'}。開啟後可能取得親密值、默契值、心動值、雙人點數、約會靈感卡、深聊卡、關係稱號或徽章。`}:{name:id,quantity:0});alert(`${it.name}\n\n數量：${it.quantity||0}\n效果：${itemEffectText(it)}\n可使用目標：${chest?'關係頁 / 錢包頁開啟':itemTargetText(it)}`)}
function confirmUseItem(){const it=itemByIdOrName(pendingUseItemId);if(!it)return closeUseItemModal();const name=it.name;closeUseItemModal();useItemNow(it.id,name)}
function logItemUse(it,effect,target='general',extra={}){state.itemUseLogs.unshift(withMeta({id:uid('itemUse'),date:todayKey(),item:it.name,itemId:it.id,quantity:1,effect,target,...extra},'itemUseLog',state));addGameLog('useItem',`使用道具：${it.name}｜${effect}`,{itemId:it.id,itemName:it.name,target,...extra})}
function useItemNow(id,name){const it=itemByIdOrName(id);if(!it)return toast('找不到道具');if(name==='抽獎券'){logItemUse(it,'前往翻牌','game');goPage('game');return}if(name==='轉盤機會'){logItemUse(it,'前往轉盤','game');goPage('game');return}if(String(name).includes('寶箱')){openChest(id);return}if(name==='補救券'){useRescueTicket(id);return}if(name==='加倍卡'){if(!consumeItem(id,1))return toast('數量不足');state.settings.activeEffects=state.settings.activeEffects||{};state.settings.activeEffects.doubleNext=true;logItemUse(it,'下一個任務點數 x2','task');saveState();renderAll();toast('加倍卡已啟用，下個任務點數 x2');return}if(name==='跳過券'){logItemUse(it,'引導至可跳過任務卡，不直接消耗','task');goPage('today');toast('請在可跳過任務卡上使用跳過券');return}if(name==='換卡券'){logItemUse(it,'引導至本期彈性任務，不直接消耗','task');goPage('today');toast('請在本期彈性任務第二次以上換卡時使用換卡券');return}if(name==='商店折價券'){if(!consumeItem(id,1))return toast('數量不足');state.settings.activeEffects=state.settings.activeEffects||{};state.settings.activeEffects.discountCoupon=true;logItemUse(it,'下次兌換獎勵可使用折價','reward');saveState();renderAll();toast('已啟用商店折價券');return}if(['火焰球','冰凍彈','破盾券','追加攻擊券','Boss 弱點卡'].includes(name)){useBossItemAction(name);return}if(name==='能量藥水'){if(!consumeItem(id,1))return toast('數量不足');addCouplePoints(10,'energyPotion','使用能量藥水轉成雙人點數',id);logItemUse(it,'雙人點數 +10','couple');saveState();renderAll();toast('已使用能量藥水，雙人點數 +10');return}if(name==='星光碎片'){if(itemQuantity('星光碎片')<5)return toast(`星光碎片 ${itemQuantity('星光碎片')}/5，集滿 5 個可合成銀寶箱`);for(let i=0;i<5;i++)consumeItem('星光碎片',1);grantItem('銀寶箱',1,'craft');logItemUse(it,'合成銀寶箱','craft');saveState();renderAll();toast('已用 5 個星光碎片合成銀寶箱');return}if(name==='地圖換算券'){if(!consumeItem(id,1))return toast('數量不足');state.activeItemEffects.unshift(withMeta({id:uid('activeEffect'),date:todayKey(),itemName:name,effect:'下一個主線任務地圖步數 +50%',target:'map',status:'active'},'activeItemEffect',state));state.mapTravelCoupons.unshift(withMeta({id:uid('mapCoupon'),date:todayKey(),couponType:'mapStepBoost',effect:'下一個主線任務地圖步數 +50%',status:'active'},'mapTravelCoupon',state));logItemUse(it,'啟用地圖步數加成','map');saveState();renderAll();toast('地圖換算券已啟用，下一個主線任務步數加成');return}toast('這個道具目前沒有可直接使用的效果')}
function useRescueTicket(itemId){
  const d=new Date();d.setDate(d.getDate()-1);const rescueDate=todayKey(d);
  const candidates=state.habits.filter(h=>h.allowRescue!==false&&!state.habitLogs.some(l=>l.date===rescueDate&&(l.habitId===h.id||l.taskId===h.id)&&!l.deletedAt));
  if(!candidates.length)return toast('昨天沒有可補救的未完成習慣');
  const list=candidates.map((h,i)=>`${i+1}. ${h.title}${h.canDoubleComplete===false?'（不可加倍）':''}`).join('\n');
  const idx=Number(prompt(`選擇要補救昨天未完成的習慣：\n${list}`,'1'))-1;const h=candidates[idx];if(!h)return toast('未選擇補救習慣');
  const opts=h.canDoubleComplete===false?['自訂補救','放棄補救']:['加倍完成','自訂補救','放棄補救'];
  const pick=Number(prompt(`選擇補救方式：\n${opts.map((o,i)=>`${i+1}. ${o}`).join('\n')}\n${h.rescueHint?`提示：${h.rescueHint}`:''}`,'1'))-1;
  const mode=opts[pick];if(!mode||mode==='放棄補救')return toast('已取消補救');
  let title=`補救：${h.title}`;let detail=mode;let points=Math.max(1,Math.round((Number(h.points)||10)*(mode==='加倍完成'?0.8:0.5)));
  if(mode==='自訂補救'){title=prompt('補救名稱',`補救：${h.title}`)||title;detail=prompt('補救內容',h.rescueHint||'請輸入今天額外完成的補救行動')||'自訂補救';points=Number(prompt('補救點數',String(points)))||points}
  if(!consumeItem(itemId,1))return toast('補救券數量不足');
  const log=withMeta({id:uid('habitLog'),date:rescueDate,habitId:h.id,taskId:h.id,title,points,type:'rescue',status:'rescued',rescueMode:mode,rescueDetail:detail,completedAt:nowIso(),countsOriginal:true,keepStreak:true},'habitLog',state);state.habitLogs.unshift(log);
  state.rescueLogs.unshift(withMeta({id:uid('rescue'),date:todayKey(),targetDate:rescueDate,habitId:h.id,habitTitle:h.title,mode,detail,points,keepStreak:true,countOriginal:true},'rescueLog',state));
  state.streakRewards.unshift(withMeta({id:uid('streakRescue'),date:todayKey(),type:'rescueTicketUsed',targetDate:rescueDate,item:'補救券',habitId:h.id},'streakReward',state));
  addPoints(points,'rescue',`補救昨天未完成：${h.title}`,h.id);addGameLog('useRescueTicket',`使用補救券補救 ${rescueDate}：${h.title}`,{targetDate:rescueDate,habitId:h.id,mode,points});saveState();renderAll();toast('已完成補救並保留連續感')}
function checkStreakRewards(){const streak=calculateStreak();const rules=[{days:3,points:10,item:'抽獎券'},{days:7,points:25,item:'補救券'},{days:14,points:50,item:'加倍卡'},{days:30,points:120,item:'金寶箱'}];for(const r of rules){const id=`streak_${r.days}_${todayKey()}`;if(streak>=r.days&&!state.streakRewards.some(x=>x.id===id)){state.streakRewards.unshift(withMeta({id,date:todayKey(),days:r.days,points:r.points,item:r.item,type:'autoReward'},'streakReward',state));addPoints(r.points,'streakReward',`連續 ${r.days} 天獎勵`,id);grantItem(r.item,1,r.item.includes('寶箱')?'chest':'reward');addGameLog('streakReward',`連續 ${r.days} 天獎勵`,{points:r.points,item:r.item});toast(`連續 ${r.days} 天，獲得 ${r.points} 點與 ${r.item}`)}}}
function markRedemptionUsed(id){const r=state.rewardRedemptions.find(x=>x.id===id);if(!r)return;r.used=true;r.usedAt=nowIso();r.updatedAt=nowIso();saveState();renderAll();toast('已標記使用')}
function noteRedemption(id){const r=state.rewardRedemptions.find(x=>x.id===id);if(!r)return;const note=prompt('輸入兌換備註',r.note||'');if(note===null)return;r.note=note;r.updatedAt=nowIso();saveState();renderAll();toast('已更新備註')}
function showTaskHelp(id,source){const t=(source==='flex'?flexMissionPool:dailyMissionPool).find(x=>x.id===id)||state.habits.find(x=>x.id===id);if(!t)return;alert(`${t.title}\n\n${t.frequencyRule?frequencyDescription(t.frequencyRule):'一天型任務'}\n${t.description||t.note||''}`)}
function modeOptions(type){return {daily:[['daily','每日']],weekly:[['count','每週幾次'],['weekdays','每週固定星期幾']],tenDays:[['count','每 10 天幾次'],['tenDaysDates','每 10 天固定第幾天']],biweekly:[['count','每雙週幾次'],['biweeklyWeekdays','每雙週固定第幾週星期幾']],monthly:[['count','每月幾次'],['monthWeeks','每月固定第幾週星期幾'],['monthDates','每月固定幾號']],quarterly:[['count','每季幾次'],['quarterMonths','每季固定第幾個月'],['quarterDates','每季固定第幾個月幾號']],yearly:[['count','每年幾次'],['yearQuarters','每年固定第幾季'],['yearMonths','每年固定幾月'],['yearDates','每年固定幾月幾號'],['yearWeeks','每年固定第幾週星期幾']]}[type]||[]}
function renderFreqUI(rule=collectRuleSafe()){const type=$('#freqType')?.value||rule.type||'daily';const opts=modeOptions(type);const modeEl=$('#freqMode');if(!modeEl)return;modeEl.innerHTML=opts.map(o=>`<option value="${o[0]}">${o[1]}</option>`).join('');modeEl.value=opts.some(o=>o[0]===rule.mode)?rule.mode:opts[0]?.[0];renderFreqDynamic(rule)}function chip(name,value,label,checked=false){return `<label class="check-chip"><input type="checkbox" name="${name}" value="${value}" ${checked?'checked':''}>${label}</label>`}function range(n,name,prefix='',checked=[]){return Array.from({length:n},(_,i)=>chip(name,i+1,`${prefix}${i+1}`,checked.includes(i+1))).join('')}function weekdayChips(checked=[]){return [1,2,3,4,5,6,7].map(i=>chip('weekdays',i,'週'+'一二三四五六日'[i-1],checked.includes(i))).join('')}
function renderFreqDynamic(rule=collectRuleSafe()){const mode=$('#freqMode')?.value;let html='';if(mode==='count')html=`<label>次數<input id="freqCount" type="number" min="1" value="${rule.count||1}"></label>`;if(mode==='weekdays')html=`<div class="check-grid">${weekdayChips(rule.weekdays)}</div>`;if(mode==='tenDaysDates')html=`<div class="check-grid">${range(10,'monthDates','第 ',rule.monthDates)}</div>`;if(mode==='biweeklyWeekdays')html=`<b>第幾週</b><div class="check-grid">${range(2,'weekNumbers','第 ',rule.weekNumbers)}</div><b>星期</b><div class="check-grid">${weekdayChips(rule.weekdays)}</div>`;if(mode==='monthWeeks')html=`<b>第幾週</b><div class="check-grid">${range(5,'monthWeeks','第 ',rule.monthWeeks)}${chip('monthWeeks','last','最後一週',rule.monthWeeks.includes('last'))}</div><b>星期</b><div class="check-grid">${weekdayChips(rule.weekdays)}</div>`;if(mode==='monthDates')html=`<div class="check-grid">${range(31,'monthDates','',rule.monthDates)}${chip('monthDates','last','月底',rule.monthDates.includes('last'))}</div>`;if(mode==='quarterMonths')html=`<div class="check-grid">${range(3,'quarterMonths','第 ',rule.quarterMonths)}</div>`;if(mode==='quarterDates')html=`<b>季內第幾個月</b><div class="check-grid">${range(3,'quarterMonths','第 ',rule.quarterMonths)}</div><b>幾號</b><div class="check-grid">${range(31,'monthDates','',rule.monthDates)}${chip('monthDates','last','月底',rule.monthDates.includes('last'))}</div>`;if(mode==='yearQuarters')html=`<div class="check-grid">${range(4,'quarters','第 ',rule.quarters)}</div>`;if(mode==='yearMonths')html=`<div class="check-grid">${range(12,'months','',rule.months)}</div>`;if(mode==='yearDates')html=`<div class="form-grid"><label>月份<input id="yearDateMonth" type="number" min="1" max="12" value="1"></label><label>日期<input id="yearDateDay" placeholder="1-31 或 last" value="1"></label></div><button class="btn ghost small" type="button" onclick="window.addYearDate()">新增月日</button><div id="yearDatesList" class="item-sub">${(rule.yearDates||[]).map(x=>`${x.month}/${x.date}`).join('、')}</div>`;if(mode==='yearWeeks')html=`<b>第幾週</b><div class="check-grid">${range(53,'yearWeeks','第 ',rule.yearWeeks)}</div><b>星期</b><div class="check-grid">${weekdayChips(rule.weekdays)}</div>`;const freqDynamicEl=$('#freqDynamic');if(!freqDynamicEl)return;freqDynamicEl.innerHTML=html||'<div class="item-sub">每日不需設定第二層條件。</div>';window.__yearDates=[...(rule.yearDates||[])];window.addYearDate=()=>{const m=Number($('#yearDateMonth').value)||1;const d=$('#yearDateDay').value==='last'?'last':Number($('#yearDateDay').value)||1;window.__yearDates.push({month:m,date:d});$('#yearDatesList').textContent=window.__yearDates.map(x=>`${x.month}/${x.date}`).join('、');updateFreqPreview()};updateFreqPreview()}
