function parseRewardRulesInput(id,habit){
  const raw=($(id)?.value||'').trim();
  if(!raw)return normalizeRewardRules([],habit);
  try{return normalizeRewardRules(JSON.parse(raw),habit)}catch(e){toast('獎勵規則資料格式錯誤，已改用預設獎勵');return normalizeRewardRules([],habit)}
}
function boolFromCheckbox(id, fallback=false){const el=$('#'+id);return el?!!el.checked:fallback}
function readRewardRules(ctx='habit'){
  const id=ctx==='assigned'?'assignRewardRules':'habitRewardRules';
  try{return JSON.parse($('#'+id)?.value||'[]')||[]}catch{return []}
}
function writeRewardRules(ctx='habit',rules=[]){
  const id=ctx==='assigned'?'assignRewardRules':'habitRewardRules';
  const el=$('#'+id);if(el)el.value=JSON.stringify(rules||[]);
  renderRewardRulesList(ctx);
}
function rewardCtxIds(ctx){
  if(ctx==='assigned')return {trigger:'assignRewardTriggerType',cond:'assignRewardConditionValue',period:'assignRewardConditionPeriod',pointsEn:'assignRewardPointsEnabled',points:'assignRewardPoints',coupleEn:'assignRewardCoupleEnabled',couple:'assignRewardCouple',itemEn:'assignRewardItemEnabled',item:'assignRewardItem',customEn:'assignRewardCustomEnabled',custom:'assignRewardCustom'};
  return {trigger:'rewardTriggerType',cond:'rewardConditionValue',period:'rewardConditionPeriod',repeat:'rewardRepeatable',note:'rewardDetailNote',pointsEn:'rewardItemPointsEnabled',points:'rewardItemPoints',expEn:'rewardItemExpEnabled',exp:'rewardItemExp',chestEn:'rewardItemChestEnabled',chest:'rewardItemChest',chestQty:'rewardItemChestQty',itemEn:'rewardItemItemEnabled',item:'rewardItemItem',itemQty:'rewardItemItemQty',bossEn:'rewardItemBossEnabled',boss:'rewardItemBoss',mapEn:'rewardItemMapEnabled',map:'rewardItemMap',badgeEn:'rewardItemBadgeEnabled',badge:'rewardItemBadge',coupleEn:'rewardItemCoupleEnabled',couple:'rewardItemCouple',relEn:'rewardItemRelationshipEnabled',rel:'rewardItemRelationship',customEn:'rewardItemCustomEnabled',custom:'rewardItemCustom'};
}
function collectRewardRuleFromFixedFields(ctx='habit'){
  const ids=rewardCtxIds(ctx),items=[];
  const add=(type,value,extra={})=>{if(value!==''&&value!==null&&value!==undefined)items.push({type,value,...extra})};
  if(boolFromCheckbox(ids.pointsEn))add('points',Number(val(ids.points))||0);
  if(ids.expEn&&boolFromCheckbox(ids.expEn))add('exp',Number(val(ids.exp))||0);
  if(ids.chestEn&&boolFromCheckbox(ids.chestEn))add('chest',val(ids.chest)||'木寶箱',{qty:Number(val(ids.chestQty))||1});
  if(boolFromCheckbox(ids.itemEn))add('item',val(ids.item)||'抽獎券',{qty:Number(val(ids.itemQty))||1});
  if(ids.bossEn&&boolFromCheckbox(ids.bossEn))add('bossDamage',Number(val(ids.boss))||0);
  if(ids.mapEn&&boolFromCheckbox(ids.mapEn))add('mapSteps',Number(val(ids.map))||0);
  if(ids.badgeEn&&boolFromCheckbox(ids.badgeEn))add('badge',val(ids.badge)||'auto');
  if(boolFromCheckbox(ids.coupleEn))add('couplePoints',Number(val(ids.couple))||0);
  if(ids.relEn&&boolFromCheckbox(ids.relEn))add('relationshipValue',Number(val(ids.rel))||0);
  if(boolFromCheckbox(ids.customEn))add('customReward',val(ids.custom)||'自訂獎勵');
  if(!items.length)items.push({type:'points',value:ctx==='assigned'?Number(val('assignPoints'))||10:Number(val('habitPoints'))||10});
  return {rewardRuleId:uid('rewardRule'),rewardTriggerType:val(ids.trigger)||'singleComplete',conditionValue:Number(val(ids.cond))||1,conditionPeriod:val(ids.period)||'none',rewardItems:items,detailNote:ids.note?val(ids.note):'',repeatable:ids.repeat?val(ids.repeat)==='true':false,enabled:true,claimedHistory:[]};
}
function rewardRuleShort(rule){return `${rewardTriggerLabel(rule.rewardTriggerType)} ${rule.conditionValue||1}${periodLabelShort(rule.conditionPeriod)}｜${(rule.rewardItems||[]).map(rewardItemLabel).join('、')||'無獎勵'}`}
function rewardTriggerLabel(v){return ({singleComplete:'每次完成',streak:'連續完成',periodCount:'週期內完成',totalCount:'累積完成',minimumComplete:'最低啟動完成',rescueComplete:'補救完成',amountComplete:'完成指定量'}[v]||v||'獎勵')}
function periodLabelShort(v){return ({none:'',daily:' / 每日',weekly:' / 每週',monthly:' / 每月',quarterly:' / 每季',yearly:' / 每年',customDays:' / 自訂天數'}[v]||'')}
function rewardItemLabel(it){const t=it.type||it.rewardType;const v=it.value??it.amount??it.name;const q=it.qty?` x${it.qty}`:'';return ({points:'點數',exp:'EXP',chest:'寶箱',item:'道具',bossDamage:'Boss 傷害',mapSteps:'地圖步數',badge:'徽章',couplePoints:'雙人點數',relationshipValue:'關係值',customReward:'自訂獎勵'}[t]||t)+` ${v}${q}`}
function renderRewardRulesList(ctx='habit'){
  const box=$('#'+(ctx==='assigned'?'assignedRewardRulesList':'rewardRulesList'));if(!box)return;
  const rules=readRewardRules(ctx);
  box.innerHTML=rules.length?rules.map((r,i)=>`<article class="item"><div class="item-top"><div><div class="item-title">${rewardRuleShort(r)}</div><div class="item-sub">${r.enabled===false?'已停用':'已啟用'}${r.detailNote?`｜${r.detailNote}`:''}</div></div><div class="actions"><button class="btn ghost small" type="button" data-edit-reward-rule="${i}" data-reward-ctx="${ctx}">編輯</button><button class="btn purple small" type="button" data-copy-reward-rule="${i}" data-reward-ctx="${ctx}">複製</button><button class="btn ghost small" type="button" data-toggle-reward-rule="${i}" data-reward-ctx="${ctx}">${r.enabled===false?'啟用':'停用'}</button><button class="btn red small" type="button" data-delete-reward-rule="${i}" data-reward-ctx="${ctx}">刪除</button></div></div></article>`).join(''):'<div class="empty">尚未新增獎勵規則。可用上方固定欄位新增，不需要填 JSON。</div>';
}
function addRewardRuleFromForm(ctx='habit'){
  const rules=readRewardRules(ctx);rules.push(collectRewardRuleFromFixedFields(ctx));writeRewardRules(ctx,rules);toast('已新增獎勵規則')
}
