function saveHabit(e){e.preventDefault();const id=$('#habitId').value||uid('habit');const base={id,title:val('habitName').trim(),description:val('habitDescription').trim(),note:val('habitNote').trim(),category:val('habitCategory'),points:Number(val('habitPoints'))||10,pack:val('habitPack'),type:val('habitPack'),taskSource:'user',isUserCreated:true,enabled:val('habitEnabled')!=='false',visibility:val('habitVisibility')||'status',allowRescue:val('habitAllowRescue')!=='false',canDoubleComplete:val('habitCanDouble')!=='false',rescueHint:val('habitRescueHint').trim(),targetAmount:Number(val('habitTargetAmount'))||1,targetUnit:val('habitTargetUnit')||'次',minimumAmount:Number(val('habitMinimumAmount'))||0,minimumPoints:Number(val('habitMinimumPoints'))||0,oncePerDay:val('habitOncePerDay')!=='false',partialAllowed:val('habitPartialAllowed')!=='false',countForShared:boolFromCheckbox('habitCountForShared',true),countForChallenge:boolFromCheckbox('habitCountForChallenge',true),countForBoss:boolFromCheckbox('habitCountForBoss',true),countForMap:boolFromCheckbox('habitCountForMap',true),countForReport:boolFromCheckbox('habitCountForReport',true),frequencyRule:collectRule()};if(!base.title)return toast('請輸入習慣名稱');base.frequency=base.frequencyRule.type;base.rewardRules=parseRewardRulesInput('#habitRewardRules',base);const idx=state.habits.findIndex(x=>x.id===id);if(idx>=0)state.habits[idx]=withMeta({...state.habits[idx],...base},'habit',state);else state.habits.push(withMeta(base,'habit',state));syncHabitRewardRuleTable(id,base.rewardRules);saveState();resetHabitForm();renderAll();toast('已儲存習慣')}
