function assignedFrequencyRule(){
  const f=val('assignFreq')||'一次性';
  const count=Number(val('assignFrequencyCount'))||1;
  if(f==='每日'||f==='一次性')return normalizeRule({type:'daily',mode:'daily',count:1});
  if(f==='每週')return normalizeRule({type:'weekly',mode:'count',count});
  if(f==='每 10 天')return normalizeRule({type:'tenDays',mode:'count',count,intervalDays:10});
  if(f==='每雙週')return normalizeRule({type:'biweekly',mode:'count',count,intervalDays:14});
  if(f==='每月')return normalizeRule({type:'monthly',mode:'count',count});
  if(f==='每季')return normalizeRule({type:'quarterly',mode:'count',count});
  if(f==='每年')return normalizeRule({type:'yearly',mode:'count',count});
  if(f==='本期')return normalizeRule({type:'weekly',mode:'count',count});
  return normalizeRule({type:'daily',mode:'daily',count:1});
}
function assignedExtraReward(){
  return {
    couplePoints:Number(val('assignExtraCouplePoints'))||0,
    item:val('assignExtraItem')||'',
    lottery:Number(val('assignExtraLottery'))||0,
    relationshipValue:Number(val('assignExtraRelationship'))||0,
    customReward:val('assignExtraCustom')||''
  };
}
function assignedExtraRewardText(extra={}){
  const parts=[];
  if(Number(extra.couplePoints||0)>0)parts.push(`雙人點數 +${extra.couplePoints}`);
  if(extra.item)parts.push(`道具：${extra.item}`);
  if(Number(extra.lottery||0)>0)parts.push(`抽獎券 +${extra.lottery}`);
  if(Number(extra.relationshipValue||0)>0)parts.push(`關係值 +${extra.relationshipValue}`);
  if(extra.customReward)parts.push(extra.customReward);
  return parts.join('、');
}
function createAssignedTask(){
  const title=val('assignTitle').trim();if(!title)return toast('請輸入指派任務名稱');
  const extra=assignedExtraReward();
  const base={id:uid('assigned'),title,description:val('assignDesc'),note:val('assignNote'),category:val('assignCategory')||'關係',taskType:val('assignType')||'side',type:val('assignType')||'side',assignerId:state.firebase?.user?.uid||'me',assignerName:state.firebase?.user?.name||'我',receiverId:'partner',receiverName:'對方',frequency:val('assignFreq')||'一次性',frequencyRule:assignedFrequencyRule(),targetAmount:Number(val('assignTargetAmount'))||1,targetUnit:val('assignTargetUnit')||'次',points:Number(val('assignPoints'))||10,oncePerDay:val('assignOncePerDay')!=='false',partialAllowed:val('assignPartial')!=='false',allowRescue:val('assignAllowRescue')!=='false',canDoubleComplete:val('assignCanDouble')!=='false',rescueHint:val('assignRescueHint')||'',visibility:val('assignVisibility')||'status',countForShared:val('assignCountShared')!=='false',countForBoss:val('assignCountBoss')!=='false',countForCoupleReport:val('assignCountReport')!=='false',extraRewards:extra,extraReward:assignedExtraRewardText(extra),needAccept:true,status:'pending'};
  base.rewardRules=parseRewardRulesInput('#assignRewardRules',base);
  if(!base.rewardRules.length)base.rewardRules=normalizeRewardRules([{rewardTriggerType:'singleComplete',conditionValue:1,conditionPeriod:'none',rewardItems:[{type:'points',value:base.points}],detailNote:'完成指派任務獎勵',repeatable:true,enabled:true}],base);
  const row=withMeta(base,'assignedTask',state);state.assignedTasks.unshift(row);
  state.assignedTaskRewards.unshift(withMeta({id:uid('assignedReward'),assignedTaskId:row.id,extraReward:row.extraReward,extraRewards:row.extraRewards,rewardRules:row.rewardRules},'assignedTaskReward',state));
  state.assignedTaskLogs.unshift(withMeta({id:uid('assignedLog'),assignedTaskId:row.id,action:'created',actorId:row.assignerId,description:`建立指派任務：${row.title}`},'assignedTaskLog',state));
  writeRewardRules('assigned',[]);['assignTitle','assignDesc','assignNote','assignReward','assignRescueHint','assignExtraCustom'].forEach(id=>{const el=$('#'+id);if(el)el.value=''});['assignExtraCouplePoints','assignExtraLottery','assignExtraRelationship'].forEach(id=>{const el=$('#'+id);if(el)el.value='0'});const item=$('#assignExtraItem');if(item)item.value='';
  saveState();renderAll();toast('已新增對方指派任務')}
function acceptAssignedTask(id){const t=state.assignedTasks.find(x=>x.id===id);if(!t)return;t.status='accepted';t.acceptedAt=nowIso();state.assignedTaskLogs.unshift(withMeta({id:uid('assignedLog'),assignedTaskId:id,action:'accepted',description:'接收方接受任務'},'assignedTaskLog',state));state.habits.push(withMeta({id:uid('habit'),title:t.title,category:t.category||'關係',points:t.points,pack:t.taskType,type:t.taskType,taskSource:'assigned',assignedTaskId:t.id,isUserCreated:false,allowRescue:t.allowRescue!==false,canDoubleComplete:t.canDoubleComplete!==false,rescueHint:t.rescueHint||'',visibility:t.visibility||'status',countForShared:t.countForShared!==false,description:t.description,targetAmount:t.targetAmount||1,targetUnit:t.targetUnit||'次',partialAllowed:t.partialAllowed!==false,rewardRules:normalizeRewardRules(t.rewardRules||[],t),frequencyRule:t.frequencyRule||normalizeRule({type:'daily',mode:'daily',count:1})},'habit',state));saveState();renderAll();toast('已接受並加入任務列表')}
function rejectAssignedTask(id){const t=state.assignedTasks.find(x=>x.id===id);if(!t)return;t.status='rejected';t.rejectedAt=nowIso();saveState();renderAll();toast('已拒絕指派任務')}
function requestAssignedChange(id,type='edit'){const t=state.assignedTasks.find(x=>x.id===id);if(!t)return;if(t.status==='completed')return toast('已完成的指派任務不可變動，只能複製成新任務');let proposedChanges={};let reason='';if(type==='edit'){const title=prompt('提出修改：任務名稱',t.title||'');if(title===null)return;const points=Number(prompt('提出修改：系統點數',t.points||10)||t.points||10);const extraReward=prompt('提出修改：指派者額外獎勵',t.extraReward||'');if(extraReward===null)return;proposedChanges={title,points,extraReward};reason=prompt('修改原因','想調整任務內容或獎勵')||'';t.status='changePending'}else{reason=prompt('刪除原因','想取消這個指派任務')||'';t.status='deletePending'}const req=withMeta({id:uid('assignedChange'),assignedTaskId:id,requesterId:t.assignerId||'me',receiverId:t.receiverId||'partner',requestType:type,proposedChanges,reason,status:'pending',createdAt:nowIso(),respondedAt:''},'assignedTaskChangeRequest',state);state.assignedTaskChangeRequests.unshift(req);state.assignedTaskLogs.unshift(withMeta({id:uid('assignedLog'),assignedTaskId:id,action:type==='edit'?'requestEdit':'requestDelete',changeRequestId:req.id,description:reason},'assignedTaskLog',state));saveState();renderAll();toast(type==='edit'?'已提出修改，等待接收方同意':'已提出刪除，等待接收方同意')}
function latestAssignedRequest(id){return (state.assignedTaskChangeRequests||[]).filter(r=>r.assignedTaskId===id&&r.status==='pending'&&!r.deletedAt).sort((a,b)=>String(b.createdAt).localeCompare(String(a.createdAt)))[0]}
function respondAssignedChange(id,approve){const t=state.assignedTasks.find(x=>x.id===id);if(!t)return;const req=latestAssignedRequest(id);if(!req)return toast('找不到待同意變更');req.status=approve?'approved':'rejected';req.respondedAt=nowIso();if(approve){if(req.requestType==='edit')Object.assign(t,req.proposedChanges||{}, {status:'accepted',updatedAt:nowIso()});else if(req.requestType==='delete'){t.status='cancelled';t.deletedAt=nowIso();}}else{t.status='accepted'}state.assignedTaskLogs.unshift(withMeta({id:uid('assignedLog'),assignedTaskId:id,action:approve?'approveChange':'rejectChange',changeRequestId:req.id,description:approve?'同意變更':'拒絕變更'},'assignedTaskLog',state));saveState();renderAll();toast(approve?'已同意變更':'已拒絕變更')}
function completeAssignedTask(id){const t=state.assignedTasks.find(x=>x.id===id);if(!t)return;if(t.status==='completed')return toast('已完成');t.status='completed';t.completedAt=nowIso();state.assignedTaskLogs.unshift(withMeta({id:uid('assignedLog'),assignedTaskId:id,action:'completed',description:`完成指派任務：${t.title}`},'assignedTaskLog',state));addPoints(Number(t.points||0),'assignedTask',`完成對方指派任務：${t.title}`,id);if(t.countForBoss!==false)applyBossDamage(Math.max(4,Math.round(Number(t.points||10)*.6)),'assignedTask',`對方指派任務：${t.title}`,id);saveState();renderAll();toast('已完成對方指派任務')}
function copyAssignedTask(id){const t=state.assignedTasks.find(x=>x.id===id);if(!t)return;const cp=withMeta({...t,id:uid('assigned'),title:`${t.title}（複製）`,status:'pending',acceptedAt:'',completedAt:'',deletedAt:null,createdAt:nowIso(),updatedAt:nowIso()},'assignedTask',state);state.assignedTasks.unshift(cp);saveState();renderAll();toast('已複製成新的指派任務')}


function completeHabitFromCard(id){
  const h=state.habits.find(x=>x.id===id&&!x.deletedAt);
  if(!h)return toast('找不到習慣');
  const ok=addLog(h,{type:'habit',periodKey:periodKey(h.frequencyRule),periodLabel:periodLabel(h.frequencyRule)});
  if(!ok)return toast('今天已完成這個習慣');
  checkDailyPackRewards(h.pack||h.type||'side');
  const pack=h.pack||h.type||'side';
  const cp=pack==='main'?3:pack==='side'?2:pack==='bonus'?1:0;
  if(cp>0)addCouplePoints(cp,'personalHabit',`個人習慣貢獻雙人點數：${h.title}`,h.id);
  saveState();renderAll();toast(`完成：${h.title}`);
}
function partialHabitFromCard(id){
  const h=state.habits.find(x=>x.id===id&&!x.deletedAt);
  if(!h)return toast('找不到習慣');
  if(h.partialAllowed===false)return toast('此習慣不允許部分完成');
  const ratio=Number(prompt('完成比例 1-100，例如 50','50')||0);
  if(!ratio||ratio<=0)return;
  const pts=Math.max(1,Math.round(Number(h.points||0)*Math.min(100,ratio)/100));
  const ok=addLog(h,{type:'partial',status:'partial',partialRatio:Math.min(100,ratio)/100,points:pts,periodKey:periodKey(h.frequencyRule),periodLabel:periodLabel(h.frequencyRule)});
  if(!ok)return toast('今天已有完成紀錄');
  saveState();renderAll();toast('已記錄部分完成');
}
function rescueHabitFromCard(id){
  const h=state.habits.find(x=>x.id===id&&!x.deletedAt);
  if(!h)return toast('找不到習慣');
  if(h.allowRescue===false)return toast('此習慣不允許補救');
  if(itemQuantity('補救券')<=0)return toast('沒有補救券');
  const mode=h.canDoubleComplete===false?'自訂補救':(confirm('要使用「加倍完成」補救嗎？按取消可輸入自訂補救。')?'加倍完成':'自訂補救');
  const note=mode==='自訂補救'?(prompt('請輸入自訂補救內容',h.rescueHint||'')||'自訂補救'):mode;
  consumeItem('補救券',1);
  const pts=Math.max(1,Math.round(Number(h.points||5)*0.5));
  const row=withMeta({id:uid('rescue'),habitId:h.id,taskId:h.id,title:h.title,date:todayKey(),mode,note,points:pts,keepStreak:true},'rescueLog',state);
  state.rescueLogs.unshift(row);
  addLog(h,{type:'rescue',status:'rescued',points:pts,periodKey:periodKey(h.frequencyRule),periodLabel:periodLabel(h.frequencyRule)});
  saveState();renderAll();toast('已使用補救券');
}

function saveReward(e){e.preventDefault();const id=$('#rewardId').value||uid('reward');const r={id,name:val('rewardName').trim(),cost:Number(val('rewardCost'))||0,category:val('rewardCategory'),stock:val('rewardStock'),weeklyLimit:val('rewardWeeklyLimit'),note:val('rewardNote')};if(!r.name)return toast('請輸入獎勵名稱');const idx=state.rewards.findIndex(x=>x.id===id);if(idx>=0)state.rewards[idx]=withMeta({...state.rewards[idx],...r},'reward',state);else state.rewards.push(withMeta(r,'reward',state));saveState();$('#rewardForm').reset();$('#rewardId').value='';$('#rewardCost').value=50;renderAll();toast('已儲存獎勵')}function editReward(id){const r=state.rewards.find(x=>x.id===id);if(!r)return;$('#rewardId').value=r.id;$('#rewardName').value=r.name||'';$('#rewardCost').value=r.cost||0;$('#rewardCategory').value=r.category||'小獎勵';$('#rewardStock').value=r.stock||'';$('#rewardWeeklyLimit').value=r.weeklyLimit||'';$('#rewardNote').value=r.note||'';goPage('rewards')}function redeemedThisWeek(rewardId){const now=new Date();const first=new Date(now);first.setDate(now.getDate()-((now.getDay()+6)%7));const start=first.toISOString().slice(0,10);return state.rewardRedemptions.filter(r=>r.rewardId===rewardId&&String(r.date||'')>=start&&!r.deletedAt).length}function redeemReward(id){const r=state.rewards.find(x=>x.id===id);if(!r)return;const redeemed=state.rewardRedemptions.filter(x=>x.rewardId===id&&!x.deletedAt).length;if(r.stock!==''&&r.stock!=null&&Number(r.stock)>=0&&redeemed>=Number(r.stock))return toast('庫存不足');if(r.weeklyLimit&&redeemedThisWeek(id)>=Number(r.weeklyLimit))return toast('本週兌換已達上限');let finalCost=Number(r.cost)||0;let discountUsed=false;const canDiscount=itemQuantity('商店折價券')>0;if(canDiscount){discountUsed=true;finalCost=Math.max(0,Math.ceil(finalCost*0.8));}if(currentPoints()<finalCost)return toast('點數不足');if(discountUsed){consumeItem('商店折價券',1);addGameLog('useDiscountCoupon',`兌換 ${r.name} 使用商店折價券`,{rewardId:id,originalCost:r.cost,finalCost});}state.rewardRedemptions.unshift(withMeta({id:uid('redeem'),rewardId:id,name:r.name,cost:Number(r.cost)||0,originalCost:Number(r.cost)||0,finalCost,date:todayKey(),used:false,usedAt:'',note:'',discountUsed},'rewardRedemption',state));spendPoints(finalCost,`兌換獎勵：${r.name}${discountUsed?'（折價券）':''}`);checkAchievements();saveState();renderAll();toast('兌換成功')}function delReward(id){state.rewards=state.rewards.filter(x=>x.id!==id);saveState();renderAll()}
function quickDrop(){const today=todayKey();if(state.gameLogs.some(x=>x.action==='quickDrop'&&x.date===today&&!x.deletedAt))return toast('今日份已領取');grantItem('抽獎券',1,'ticket');addPoints(5,'drop','今日小補給');addGameLog('quickDrop','今日小補給',{item:'抽獎券',points:5});state.itemUseLogs.unshift(withMeta({id:uid('itemUse'),date:today,item:'今日小補給',description:'每日限領一次'},'itemUseLog',state));checkAchievements();saveState();renderAll();toast('獲得抽獎券 1 張')}
function pickPrize(list,seed=''){const total=list.reduce((s,x)=>s+(x.weight||1),0);let r=Math.random()*total;for(const p of list){r-=p.weight||1;if(r<=0)return p}return list[list.length-1]}
function newFlip(slot=0){if(!consumeItem('抽獎券',1))return toast('需要抽獎券');const prizes=[
  {type:'points',label:'+5 點',points:5,weight:18},{type:'points',label:'+10 點',points:10,weight:16},{type:'points',label:'+30 點',points:30,weight:6},
  {type:'item',label:'補救券',item:'補救券',itemType:'rescue',weight:9},{type:'item',label:'加倍卡',item:'加倍卡',itemType:'booster',weight:8},{type:'item',label:'商店折價券',item:'商店折價券',itemType:'discount',weight:7},
  {type:'blessing',label:'今日祝福語',message:'今天不用完美，只要比昨天多前進一點。',weight:12},
  {type:'hiddenMission',label:'隱藏任務',item:'隱藏任務券',itemType:'ticket',message:'解鎖一張隱藏任務券，可在後續任務系統使用。',weight:7},
  {type:'fragment',label:'寶箱碎片',item:'寶箱碎片',itemType:'fragment',weight:17}
];const prize=pickPrize(prizes);let desc=`翻牌獎勵：${prize.label}`;const payload={slot,prizeType:prize.type,label:prize.label};if(prize.type==='points'){addPoints(prize.points,'flip',desc,'flip');payload.points=prize.points}else if(prize.type==='item'||prize.type==='hiddenMission'||prize.type==='fragment'){grantItem(prize.item,1,prize.itemType);payload.item=prize.item;if(prize.item==='寶箱碎片'&&itemQuantity('寶箱碎片')>=3){consumeItem('寶箱碎片',3);grantItem('木寶箱',1,'chest');desc+='，集滿 3 片自動合成木寶箱';payload.autoCraft='木寶箱'}}else if(prize.type==='blessing'){payload.message=prize.message;desc+=`：${prize.message}`}addGameLog('flip',desc,payload);checkAchievements();saveState();renderAll();toast(desc)}
function spinWheel(){const usedToday=state.gameLogs.filter(x=>x.date===todayKey()&&x.action==='spinWheel'&&!x.deletedAt).length;if(usedToday>=3)return toast('今日轉盤已達 3 次上限');if(!consumeItem('轉盤機會',1))return toast('需要轉盤機會，完成每日任務包可取得');const prizes=[
  {type:'double',label:'下一個任務點數 x2',weight:12},{type:'points',label:'+15 點',points:15,weight:18},{type:'points',label:'+40 點',points:40,weight:7},
  {type:'discount',label:'商店折扣券',weight:12},{type:'rest',label:'休息券',weight:9},{type:'randomTask',label:'隨機任務券',weight:12},
  {type:'item',label:'抽獎券 +2',item:'抽獎券',qty:2,itemType:'ticket',weight:14},{type:'item',label:'銀寶箱',item:'銀寶箱',qty:1,itemType:'chest',weight:5}
];const prize=pickPrize(prizes);let desc=`轉盤獎勵：${prize.label}`;const payload={prizeType:prize.type,label:prize.label};if(prize.type==='double'){state.settings.activeEffects=state.settings.activeEffects||{};state.settings.activeEffects.doubleNext=true}else if(prize.type==='points'){addPoints(prize.points,'spinWheel',desc,'spinWheel');payload.points=prize.points}else if(prize.type==='discount'){grantItem('商店折價券',1,'discount');payload.item='商店折價券'}else if(prize.type==='rest'){grantItem('休息券',1,'rest');payload.item='休息券'}else if(prize.type==='randomTask'){grantItem('隨機任務券',1,'ticket');payload.item='隨機任務券'}else if(prize.type==='item'){grantItem(prize.item,prize.qty||1,prize.itemType);payload.item=prize.item;payload.qty=prize.qty||1}addGameLog('spinWheel',desc,payload);checkAchievements();saveState();renderAll();toast(desc)}
function openChest(id){const c=state.gameItems.find(x=>x.id===id);if(!c||Number(c.quantity||0)<=0)return toast('目前沒有這個寶箱');if(!String(c.name||'').includes('寶箱'))return toast('這不是寶箱');c.quantity=Number(c.quantity||0)-1;c.updatedAt=nowIso();const name=c.name;const rewards=chestRewards(name);const payload={chestId:id,chestName:name,rewards:[]};let desc=`開啟${name}`;for(const r of rewards){if(r.points){addPoints(r.points,'chest',`${name}：+${r.points} 點`,id);payload.rewards.push({type:'points',points:r.points})}if(r.item){grantItem(r.item,r.qty||1,r.itemType||'item');payload.rewards.push({type:'item',item:r.item,qty:r.qty||1})}if(r.badge){const badge=withMeta({id:`badge_${r.badge}_${Date.now()}`,date:todayKey(),name:r.badge,source:'chest',chestName:name,unlockedAt:nowIso()},'achievement',state);state.achievements.unshift(badge);payload.rewards.push({type:'badge',badge:r.badge})}}addGameLog('openChest',`${desc}：${payload.rewards.map(r=>r.points?`+${r.points}點`:r.item?`${r.item}x${r.qty}`:`徽章:${r.badge}`).join('、')}`,payload);checkAchievements();unlockStoryChapters();saveState();renderAll();toast(`${name}開啟成功`)}
function chestRewards(name){if(name==='銀寶箱')return [{points:35},{item:'抽獎券',qty:2,itemType:'ticket'},{item:'加倍卡',qty:1,itemType:'booster'}];if(name==='金寶箱')return [{points:80},{item:'抽獎券',qty:3,itemType:'ticket'},{item:'補救券',qty:1,itemType:'rescue'},{item:'加倍卡',qty:1,itemType:'booster'},{item:'商店折價券',qty:1,itemType:'discount'},{badge:'金寶箱探險家'}];if(name==='雙人寶箱')return [{points:50},{item:'抽獎券',qty:2,itemType:'ticket'},{item:'補救券',qty:1,itemType:'rescue'},{item:'徽章碎片',qty:2,itemType:'badge'},{badge:'雙人默契寶箱'}];return [{points:20},{item:'抽獎券',qty:1,itemType:'ticket'},{item:'補救券',qty:1,itemType:'rescue'}]}

function makeCode(){const chars='ABCDEFGHJKLMNPQRSTUVWXYZ23456789';return Array.from({length:6},()=>chars[Math.floor(Math.random()*chars.length)]).join('')}function createRoom(){const code=makeCode();state.room={id:code,inviteCode:code,name:val('roomName')||'我們的生活任務',members:[{id:state.firebase?.user?.uid||'me',name:state.firebase?.user?.name||'我',email:state.firebase?.user?.email||'本機成員',joinedAt:nowIso()}]};saveState();renderAll();toast(`已建立房間：${code}`)}async function joinRoom(){const code=val('inviteCode').trim().toUpperCase();if(!code)return toast('請輸入邀請碼');state.room.id=code;state.room.inviteCode=code;state.room.name=val('roomName')||'我們的生活任務';state.room.members=[{id:state.firebase?.user?.uid||'me',name:state.firebase?.user?.name||'我',email:state.firebase?.user?.email||'本機成員',joinedAt:nowIso()},{id:'partner',name:'對方',email:'等待同步'}];try{await pullRoomFromCloud(code)}catch{}saveState();renderAll();toast(`已加入房間：${code}`)}function leaveRoom(){state.room={id:'local',name:'',inviteCode:'',members:[]};saveState();renderAll();toast('已離開房間')}function supportMeta(type){return {
  encourage:{label:'鼓勵訊息',relation:3,couplePoints:5,item:'',effect:'傳送鼓勵訊息'},
  lotterySupply:{label:'抽獎券補給',relation:2,couplePoints:0,item:'抽獎券',effect:'送對方抽獎券 +1'},
  bossAssist:{label:'Boss 助攻卡',relation:2,couplePoints:0,item:'Boss 助攻卡',effect:'對方可選擇使用，使下一次 Boss 傷害 +20%'},
  rescueSupport:{label:'補救支援券',relation:3,couplePoints:0,item:'補救支援券',effect:'對方使用補救時可得到額外點數或關係值'},
  mapSupport:{label:'地圖支援券',relation:2,couplePoints:0,item:'地圖支援券',effect:'對方可選擇使用，使地圖步數加成'},
  emotionSupply:{label:'情緒補給',relation:4,couplePoints:5,item:'能量藥水',effect:'不造成任務壓力的能量補給'},
  sharedAssist:{label:'共同任務助攻',relation:2,couplePoints:5,item:'共同任務助攻卡',effect:'下一次共同任務貢獻 +1'}
}[type]||{label:type,relation:1,couplePoints:0,item:'',effect:'支援對方'}}
function sendSupport(e){e.preventDefault();const to=state.users.find(u=>u.id===val('supportTarget'))||state.users[1];const meta=supportMeta(val('supportType'));const message=val('supportMessage')||'今天辛苦了，我支援你一點能量！';const rec=withMeta({id:uid('support'),date:todayKey(),toId:to.id,toName:to.name,type:meta.label,supportType:val('supportType'),message,effect:meta.effect,relationValue:meta.relation,couplePoints:meta.couplePoints,item:meta.item},'support',state);state.supportLogs.unshift(rec);if(meta.item)grantItem(meta.item,1,'support');if(meta.couplePoints)addCouplePoints(meta.couplePoints,'support',`支援對方：${meta.label}`,rec.id);state.relationshipLogs.unshift(withMeta({id:uid('rel'),date:todayKey(),title:`支援對方：${meta.label}`,description:message,intimacy:meta.relation,harmony:0,source:'support',supportId:rec.id},'relationship',state));if(['bossAssist','rescueSupport','mapSupport','sharedAssist'].includes(val('supportType'))){state.itemUseLogs.unshift(withMeta({id:uid('itemUse'),date:todayKey(),item:meta.item||meta.label,quantity:1,effect:meta.effect,target:'partnerSupport',status:'available',supportId:rec.id},'itemUseLog',state));}
addGameLog('supportPartner',`支援對方：${meta.label}`,{toId:to.id,supportType:val('supportType'),item:meta.item,effect:meta.effect});contributeCoupleProgress(1,'support',`支援對方：${meta.label}`,{relatedId:to.id});$('#supportMessage').value='';saveState();renderAll();toast(`已送出支援：${meta.label}`)}
function relationshipCard(table,id){return (state[table]||[]).find(c=>c.id===id&&!c.deletedAt)}
function drawRelationshipCard(table,type){
  const cutoff=new Date();cutoff.setDate(cutoff.getDate()-14);
  const recentSem=new Set((state.cardDrawLogs||[]).filter(l=>l.type===type&&!l.deletedAt&&new Date(l.date||l.createdAt||0)>=cutoff).map(l=>l.semanticKey).filter(Boolean));
  const recentIdea=new Set((state.cardDrawLogs||[]).filter(l=>l.type===type&&!l.deletedAt&&new Date(l.date||l.createdAt||0)>=cutoff).map(l=>l.ideaKey).filter(Boolean));
  const pool=(state[table]||[]).filter(c=>c.enabled!==false&&!recentSem.has(c.semanticKey)&&!recentIdea.has(c.ideaKey));
  const src=pool.length?pool:(state[table]||[]).filter(c=>c.enabled!==false);
  if(!src.length)return null;
  const card=src[Math.floor(Math.random()*src.length)];
  state.cardDrawLogs.unshift(withMeta({id:uid('cardDraw'),date:todayKey(),type,cardId:card.id,title:card.title,semanticKey:card.semanticKey,ideaKey:card.ideaKey},'cardDrawLog',state));
  return card
}
function applyRelationshipReward(card,source,desc){const r=card?.reward||{};state.relationshipStats=state.relationshipStats||{intimacy:0,chemistry:0,heartbeat:0};state.relationshipStats.intimacy=Number(state.relationshipStats.intimacy||0)+Number(r.intimacy||0);state.relationshipStats.chemistry=Number(state.relationshipStats.chemistry||0)+Number(r.chemistry||0);state.relationshipStats.heartbeat=Number(state.relationshipStats.heartbeat||state.relationshipStats.companionship||0)+Number((r.heartbeat ?? r.companionship ?? 0));state.relationshipStats.updatedAt=nowIso();if(r.couplePoints)addCouplePoints(Number(r.couplePoints)||0,source,desc,card?.id);state.relationshipLogs.unshift(withMeta({id:uid('rel'),date:todayKey(),action:source,cardId:card?.id,title:card?.title,content:card?.content,intimacy:r.intimacy||0,chemistry:r.chemistry||0,heartbeat:(r.heartbeat ?? r.companionship ?? 0),couplePoints:r.couplePoints||0},'relationshipLog',state));}
function ensureRelCurrent(){state.currentRelationshipCards=state.currentRelationshipCards||{};if(state.currentRelationshipCards.date!==todayKey()){state.currentRelationshipCards.date=todayKey();state.currentRelationshipCards.closeTodaySwapped=false;const c=drawRelationshipCard('closeTodayCards','closeToday');if(c)state.currentRelationshipCards.closeTodayId=c.id;const q=drawRelationshipCard('chemistryChallengeCards','chemistry');if(q)state.currentRelationshipCards.chemistryId=q.id;const d=drawRelationshipCard('dateIdeaCards','dateIdea');if(d)state.currentRelationshipCards.dateIdeaId=d.id;const t=drawRelationshipCard('deepTalkCards','deepTalk');if(t)state.currentRelationshipCards.deepTalkId=t.id;}}
function completeCurrentCouple(){ensureRelCurrent();const card=relationshipCard('closeTodayCards',state.currentRelationshipCards.closeTodayId);if(!card)return toast('找不到今日靠近一點');if((state.relationshipLogs||[]).some(l=>l.date===todayKey()&&l.cardId===card.id&&l.action==='completeCloseToday'&&!l.deletedAt))return toast('今日靠近一點已完成');applyRelationshipReward(card,'completeCloseToday',`完成今日靠近一點：${card.title}`);state.relationshipStats.lastCloseTodayDate=todayKey();state.relationshipStats.closeTodayStreak=Number(state.relationshipStats.closeTodayStreak||0)+1;if(state.relationshipStats.closeTodayStreak%3===0)grantRelationshipChest('今日靠近一點連續完成');contributeCoupleProgress(1,'closeToday',`今日靠近一點：${card.title}`,{cardId:card.id});saveState();renderAll();toast('已完成今日靠近一點')}
function completeCouple(id){const t=state.coupleTasks.find(x=>x.id===id);if(!t)return;applyRelationshipReward({id:t.id,title:t.title,content:t.description,reward:{intimacy:t.intimacy||0,chemistry:t.harmony||0,heartbeat:t.companionship||0,couplePoints:5}},'coupleTask',`完成情侶任務：${t.title}`);saveState();renderAll();toast(`完成情侶任務：${t.title}`)}
function changeCoupleTask(){ensureRelCurrent();if(state.currentRelationshipCards.closeTodaySwapped)return toast('今日已換過');const c=drawRelationshipCard('closeTodayCards','closeToday');if(c){state.currentRelationshipCards.closeTodayId=c.id;state.currentRelationshipCards.closeTodaySwapped=true;saveState();renderAll();toast('已換今日靠近一點')}else toast('沒有可換卡片')}

function chemHash(s){let h=2166136261;for(let i=0;i<String(s).length;i++){h^=String(s).charCodeAt(i);h=Math.imul(h,16777619)}return h>>>0}
function currentChemistryCardForAction(){state.currentRelationshipCards=state.currentRelationshipCards||{};let id=state.currentRelationshipCards.chemistryChoiceId;let card=chemistryChoiceCards.find(x=>x.id===id);if(!card){card=chemistryChoiceCards[chemHash(`${todayKey()}_${getCurrentUserId(state)}_chemistryChoice`)%chemistryChoiceCards.length];state.currentRelationshipCards.chemistryChoiceId=card?.id||'';}return card||chemistryChoiceCards[0]}
function chemistryAnswersForSession(sessionId){return (state.chemistryChallengeAnswers||[]).filter(a=>a.sessionId===sessionId&&!a.deletedAt)}
function hasAnsweredChemistry(sessionId,userId){return chemistryAnswersForSession(sessionId).some(a=>String(a.userId)===String(userId))}
function selectChemistryOption(idx,btnEl){const hidden=$('#selectedChemistryOption');if(hidden)hidden.value=String(idx);const box=btnEl?.closest?.('.chemistry-choice-card');box?.querySelectorAll?.('[data-chemistry-option]')?.forEach(b=>b.classList.remove('selected'));btnEl?.classList?.add('selected')}
function nextChemistryChoice(){const c=state.currentRelationshipCards=state.currentRelationshipCards||{};const old=c.chemistryChoiceId;const seed=`${todayKey()}_${getCurrentUserId(state)}_${Date.now()}_${Math.random()}`;let card=chemistryChoiceCards[chemHash(seed)%chemistryChoiceCards.length]||chemistryChoiceCards[0];if(chemistryChoiceCards.length>1){let guard=0;while(card?.id===old&&guard<10){card=chemistryChoiceCards[chemHash(seed+'_'+guard)%chemistryChoiceCards.length];guard++;}}
c.chemistryChoiceId=card?.id||'';saveState();renderAll();toast('已換一題，尚未送出，不會同步給對方')}
function pendingChemistryForPartner(){const me=getCurrentUserId(state),partner=getPartnerUserId(state),roomId=getCurrentRoomId(state);return (state.chemistryChallengeSessions||[]).filter(s=>!s.deletedAt&&s.roomId===roomId&&s.dateKey===todayKey()&&(s.status||'waiting')==='waiting'&&hasAnsweredChemistry(s.id,me)&&!hasAnsweredChemistry(s.id,partner))}
function todayCreatedChemistryCount(){const me=getCurrentUserId(state),roomId=getCurrentRoomId(state);return (state.chemistryChallengeSessions||[]).filter(s=>!s.deletedAt&&s.roomId===roomId&&s.dateKey===todayKey()&&String(s.createdBy)===String(me)).length}
function submitChemistryChoice(){const selected=$('#selectedChemistryOption')?.value;if(selected===''||selected==null)return toast('請先選擇一個答案');const optionIndex=Number(selected);const activeId=$('#activeChemistrySession')?.value||'';let session=activeId?(state.chemistryChallengeSessions||[]).find(s=>s.id===activeId&&!s.deletedAt):null;const me=getCurrentUserId(state);if(session&&hasAnsweredChemistry(session.id,me))return toast('你已回答這一題');if(!session){if(todayCreatedChemistryCount()>=10)return toast('今天已建立 10 題默契挑戰，明天再繼續吧');if(pendingChemistryForPartner().length>=20)return toast('對方還有很多題還沒回答，先等等對方吧。');const card=currentChemistryCardForAction();session=createChemistrySessionBase({roomId:getCurrentRoomId(state),dateKey:todayKey(),cardId:card.id,questionTitle:card.title,options:card.options,category:card.category,intensity:card.intensity,createdBy:me,targetUserIds:[me,getPartnerUserId(state)].filter(Boolean)},state);state.chemistryChallengeSessions.unshift(session)}const opts=Array.isArray(session.options)?session.options:[];const answer=createChemistryAnswerBase({sessionId:session.id,roomId:session.roomId,userId:me,optionIndex,optionText:opts[optionIndex]||'',options:opts},state);state.chemistryChallengeAnswers.unshift(answer);session.updatedAt=nowIso();settleChemistryIfReady(session.id);saveState();renderAll();toast(session.status==='completed'?'雙方已回答，已完成比對':'你已回答，等待對方回答中')}
function settleChemistryIfReady(sessionId){const session=(state.chemistryChallengeSessions||[]).find(s=>s.id===sessionId&&!s.deletedAt);if(!session||session.status==='completed')return;const answers=chemistryAnswersForSession(sessionId);const unique=[];const seen=new Set();for(const a of answers){const uid=String(a.userId||'');if(!seen.has(uid)){seen.add(uid);unique.push(a)}}if(unique.length<2)return;const a=unique[0],b=unique[1];const matched=Number(a.optionIndex)===Number(b.optionIndex);session.status='completed';session.result=matched?'matched':'different';session.matchedOptionIndex=matched?Number(a.optionIndex):null;session.completedAt=nowIso();session.updatedAt=nowIso();if(session.rewardsGranted)return;const chemistryGain=matched?12:3;state.relationshipStats=state.relationshipStats||{id:'relationship_stats_main',intimacy:0,chemistry:0,heartbeat:0,companionship:0};state.relationshipStats.chemistry=Number(state.relationshipStats.chemistry||0)+chemistryGain;state.relationshipStats.updatedAt=nowIso();state.relationshipLogs.unshift(withMeta({id:uid('relChem'),date:todayKey(),action:matched?'chemistryChoiceMatched':'chemistryChoiceDifferent',source:'chemistryChoice',sourceLogId:session.id,cardId:session.cardId,title:`默契挑戰：${session.questionTitle}`,description:matched?'雙方答案相同':'雙方答案不同但已完成互動',chemistry:chemistryGain,intimacy:0,heartbeat:0,companionship:0,couplePoints:matched?5:0,result:session.result},'relationshipLog',state));if(matched)addCouplePoints(5,'chemistryChoice',`默契挑戰答案相同：${session.questionTitle}`,session.id);state.cardCollectionLogs=Array.isArray(state.cardCollectionLogs)?state.cardCollectionLogs:[];state.cardCollectionLogs.unshift(withMeta({id:uid('cardLog'),date:todayKey(),type:'chemistryChoice',action:matched?'matched':'different',cardId:session.cardId,title:session.questionTitle,sessionId:session.id,result:session.result},'cardCollectionLog',state));state.coupleBattleReports=Array.isArray(state.coupleBattleReports)?state.coupleBattleReports:[];state.coupleBattleReports.unshift(withMeta({id:uid('coupleReport'),scope:'chemistryChoice',date:todayKey(),sessionId:session.id,text:`默契挑戰「${session.questionTitle}」${matched?'答案相同，獲得默契值 +12、雙人點數 +5':'答案不同，獲得參與默契值 +3'}`},'coupleBattleReport',state));addGameLog('chemistryChoiceComplete',`完成默契挑戰：${session.questionTitle}`,{sessionId:session.id,result:session.result,chemistryGain,couplePoints:matched?5:0});session.rewardsGranted=true}
function checkHarmony(){ensureRelCurrent();const a=val('harmonyA').trim(),b=val('harmonyB').trim();if(!a||!b)return toast('請兩人都輸入答案');const card=relationshipCard('chemistryChallengeCards',state.currentRelationshipCards.chemistryId);const ok=a.trim().toLowerCase()===b.trim().toLowerCase();if(card){if(ok){applyRelationshipReward(card,'chemistrySuccess',`默契挑戰成功：${card.title}`);contributeCoupleProgress(1,'chemistry','默契挑戰成功',{cardId:card.id});}else{const small={intimacy:1,chemistry:3,heartbeat:1,couplePoints:2};state.relationshipStats=state.relationshipStats||{intimacy:0,chemistry:0,heartbeat:0};state.relationshipStats.intimacy=Number(state.relationshipStats.intimacy||0)+small.intimacy;state.relationshipStats.chemistry=Number(state.relationshipStats.chemistry||0)+small.chemistry;state.relationshipStats.heartbeat=Number(state.relationshipStats.heartbeat||0)+small.heartbeat;addCouplePoints(small.couplePoints,'chemistryTry','默契挑戰答案不同，但更了解彼此',card.id);state.relationshipLogs.unshift(withMeta({id:uid('rel'),date:todayKey(),action:'chemistryTry',cardId:card.id,title:card.title,myAnswer:a,partnerAnswer:b,intimacy:small.intimacy,chemistry:small.chemistry,heartbeat:small.heartbeat,couplePoints:small.couplePoints},'relationshipLog',state));}}
$('#harmonyResult').innerHTML=`<article class="item ${ok?'done':''}"><div class="item-title">${ok?'默契成功':'答案不同，也有收穫'}</div><div class="item-sub">${ok?'兩人答案一致，默契值提升。':'你們多理解彼此一點，仍獲得少量默契值與雙人點數。'}</div></article>`;saveState();renderAll();toast(ok?'默契成功':'答案不同，也有收穫')}
function nextHarmony(){const q=drawRelationshipCard('chemistryChallengeCards','chemistry');if(q)state.currentRelationshipCards.chemistryId=q.id;$('#harmonyA').value='';$('#harmonyB').value='';saveState();renderAll();toast('已換默契題')}
function drawDateCard(){const c=drawRelationshipCard('dateIdeaCards','dateIdea');if(c)state.currentRelationshipCards.dateIdeaId=c.id;saveState();renderAll();toast('已抽約會靈感卡')}
function drawTalkCard(){const c=drawRelationshipCard('deepTalkCards','deepTalk');if(c)state.currentRelationshipCards.deepTalkId=c.id;saveState();renderAll();toast('已抽深聊卡')}
function currentCardByType(type){ensureRelCurrent();if(type==='dateIdea')return relationshipCard('dateIdeaCards',state.currentRelationshipCards.dateIdeaId);if(type==='deepTalk')return relationshipCard('deepTalkCards',state.currentRelationshipCards.deepTalkId);return relationshipCard('closeTodayCards',state.currentRelationshipCards.closeTodayId)}
function collectCurrentCard(type){const c=currentCardByType(type);if(!c)return toast('沒有卡片');state.cardCollectionLogs.unshift(withMeta({id:uid('cardCollect'),date:todayKey(),type,cardId:c.id,title:c.title,action:'collect'},'cardCollectionLog',state));saveState();renderAll();toast('已收藏卡片')}


function currentLetterPromptForAction(){const c=state.currentRelationshipCards=state.currentRelationshipCards||{};let prompt=relationshipLetterPrompts.find(x=>x.id===c.letterPromptId);if(!prompt){prompt=relationshipLetterPrompts[Math.abs(chemHash(`${todayKey()}_${getCurrentUserId(state)}_letter_${Date.now()}`))%relationshipLetterPrompts.length]||relationshipLetterPrompts[0];c.letterPromptId=prompt?.id||'';}return prompt||relationshipLetterPrompts[0]}
function drawLetterPrompt(){const old=state.currentRelationshipCards?.letterPromptId;const seed=`${todayKey()}_${getCurrentUserId(state)}_${Date.now()}_${Math.random()}`;let prompt=relationshipLetterPrompts[chemHash(seed)%relationshipLetterPrompts.length]||relationshipLetterPrompts[0];let guard=0;while(prompt?.id===old&&guard<10){prompt=relationshipLetterPrompts[chemHash(seed+'_'+guard)%relationshipLetterPrompts.length]||relationshipLetterPrompts[0];guard++;}state.currentRelationshipCards=state.currentRelationshipCards||{};state.currentRelationshipCards.letterPromptId=prompt?.id||'';saveState();renderAll();toast('已換一題，尚未送出，不會同步給對方')}
function addRelationValuesForLetter({intimacy=0,heartbeat=0,source='letter',sourceLogId='',title='',description=''}){state.relationshipStats=state.relationshipStats||{id:'relationship_stats_main',intimacy:0,chemistry:0,heartbeat:0,companionship:0};state.relationshipStats.intimacy=Number(state.relationshipStats.intimacy||0)+Number(intimacy||0);state.relationshipStats.heartbeat=Number(state.relationshipStats.heartbeat??state.relationshipStats.companionship??0)+Number(heartbeat||0);state.relationshipStats.companionship=Number(state.relationshipStats.companionship||0)+Number(heartbeat||0);state.relationshipStats.updatedAt=nowIso();state.relationshipLogs.unshift(withMeta({id:uid('relLetter'),date:todayKey(),action:source,source,sourceLogId,title,description,intimacy,chemistry:0,heartbeat,companionship:heartbeat,couplePoints:0},'relationshipLog',state));}
function sendCoupleLetter(){const content=val('letterContent').trim();if(!content)return toast('請先寫下想給對方的內容');const prompt=currentLetterPromptForAction();const letter=createCoupleLetterBase({roomId:getCurrentRoomId(state),dateKey:todayKey(),promptId:prompt.id,promptTitle:prompt.title,promptType:prompt.type||'letter',fromUserId:getCurrentUserId(state),toUserId:getPartnerUserId(state),content,status:'sent',isFavorite:false},state);state.coupleLetters.unshift(letter);state.coupleLetterLogs.unshift(createCoupleLetterLogBase({letterId:letter.id,roomId:letter.roomId,actionType:'sent',userId:getCurrentUserId(state),note:'送出今日小信'},state));addRelationValuesForLetter({intimacy:5,heartbeat:3,source:'letterSent',sourceLogId:letter.id,title:`送出小信：${prompt.title}`,description:content});addGameLog('coupleLetterSent',`送出今日小信：${prompt.title}`,{letterId:letter.id,promptId:prompt.id});const input=$('#letterContent');if(input)input.value='';saveState();renderAll();toast('已送出小信，對方之後上線就能看到')}
function markLetterRead(id){const l=(state.coupleLetters||[]).find(x=>x.id===id&&!x.deletedAt);if(!l)return;if(String(l.toUserId)!==String(getCurrentUserId(state)))return toast('只有收件人可以標記已讀');if(l.status==='read'||l.status==='replied')return toast('這封信已讀過');l.status='read';l.readAt=nowIso();l.updatedAt=nowIso();l.readRewardGranted=true;state.coupleLetterLogs.unshift(createCoupleLetterLogBase({letterId:l.id,roomId:l.roomId,actionType:'read',userId:getCurrentUserId(state),note:'標記已讀'},state));addRelationValuesForLetter({intimacy:2,heartbeat:0,source:'letterRead',sourceLogId:l.id,title:`已讀小信：${l.promptTitle}`,description:l.content});addGameLog('coupleLetterRead',`已讀小信：${l.promptTitle}`,{letterId:l.id});saveState();renderAll();toast('已標記已讀')}
function toggleLetterFavorite(id){const l=(state.coupleLetters||[]).find(x=>x.id===id&&!x.deletedAt);if(!l)return;l.isFavorite=!l.isFavorite;l.updatedAt=nowIso();state.coupleLetterLogs.unshift(createCoupleLetterLogBase({letterId:l.id,roomId:l.roomId,actionType:l.isFavorite?'favorite':'unfavorite',userId:getCurrentUserId(state),note:l.isFavorite?'收藏小信':'取消收藏'},state));saveState();renderAll();toast(l.isFavorite?'已收藏小信':'已取消收藏')}
function replyLetter(id){const l=(state.coupleLetters||[]).find(x=>x.id===id&&!x.deletedAt);if(!l)return;const text=prompt('回覆這封小信', '');if(text===null)return;const content=text.trim();if(!content)return toast('請輸入回覆內容');const reply=createCoupleLetterReplyBase({letterId:l.id,roomId:l.roomId,fromUserId:getCurrentUserId(state),toUserId:l.fromUserId,content},state);state.coupleLetterReplies.unshift(reply);l.status='replied';l.updatedAt=nowIso();state.coupleLetterLogs.unshift(createCoupleLetterLogBase({letterId:l.id,roomId:l.roomId,actionType:'reply',userId:getCurrentUserId(state),note:'回覆小信'},state));addRelationValuesForLetter({intimacy:5,heartbeat:5,source:'letterReply',sourceLogId:reply.id,title:`回覆小信：${l.promptTitle}`,description:content});grantRelationshipChest('今日小信箱回覆');state.relationshipChestLogs=Array.isArray(state.relationshipChestLogs)?state.relationshipChestLogs:[];state.relationshipChestLogs.unshift(withMeta({id:uid('relChestLog'),date:todayKey(),action:'progress',source:'letterReply',letterId:l.id,replyId:reply.id,note:'小信箱回覆推進關係寶箱'},'relationshipChestLog',state));addGameLog('coupleLetterReply',`回覆今日小信：${l.promptTitle}`,{letterId:l.id,replyId:reply.id});saveState();renderAll();toast('已回覆小信')}

function relStats(){state.relationshipStats=state.relationshipStats||{}; if(!('heartbeat' in state.relationshipStats))state.relationshipStats.heartbeat=Number(state.relationshipStats.companionship||0)||0; return state.relationshipStats}
function normalizeWishStatus(w){if(w.status==='已完成'||w.status==='completed')return '已完成';const ready=Number(w.investedIntimacy||0)>=Number(w.requiredIntimacy||0)&&Number(w.investedChemistry||0)>=Number(w.requiredChemistry||0)&&Number(w.investedHeartbeat||0)>=Number(w.requiredHeartbeat||0);const invested=Number(w.investedIntimacy||0)+Number(w.investedChemistry||0)+Number(w.investedHeartbeat||0);return ready?'已達標':invested>0?'累積中':'想做'}
function wishPayload(base={}){
  return withMeta({id:base.id||uid('wish'),title:base.title||val('wishTitle').trim(),description:base.description||val('wishDescription').trim(),category:base.category||val('wishCategory')||'其他',requiredIntimacy:Number((base.requiredIntimacy ?? val('wishRequiredIntimacy') ?? 120))||0,investedIntimacy:Number(base.investedIntimacy||0)||0,requiredChemistry:Number((base.requiredChemistry ?? val('wishRequiredChemistry') ?? 80))||0,investedChemistry:Number(base.investedChemistry||0)||0,requiredHeartbeat:Number((base.requiredHeartbeat ?? val('wishRequiredHeartbeat') ?? 100))||0,investedHeartbeat:Number(base.investedHeartbeat||0)||0,excitementLevel:base.excitementLevel||val('wishLevel')||'3',status:base.status||'想做',source:base.source||'custom',sourceCardId:base.sourceCardId||'',sourceType:base.sourceType||'',completedAt:base.completedAt||'',note:base.note||''},'coupleWish',state);
}
function addCurrentCardToWish(type){const c=currentCardByType(type);if(!c)return toast('沒有卡片');const w=wishPayload({title:c.title,description:c.content||'',category:c.category||'其他',requiredIntimacy:type==='dateIdea'?90:120,requiredChemistry:type==='deepTalk'?100:50,requiredHeartbeat:type==='dateIdea'?160:80,excitementLevel:'3',source:'card',sourceCardId:c.id,sourceType:type});state.coupleWishPool.unshift(w);state.coupleWishLogs.unshift(withMeta({id:uid('wishLog'),date:todayKey(),wishId:w.id,action:'create',amount:0,note:'由卡片加入願望池',cardId:c.id,title:c.title},'coupleWishLog',state));saveState();renderAll();toast('已加入雙人願望池')}
function completeCurrentCard(type){const c=currentCardByType(type);if(!c)return toast('沒有卡片');applyRelationshipReward(c,type==='dateIdea'?'completeDateIdea':'completeDeepTalk',`${type==='dateIdea'?'完成約會靈感卡':'完成深聊卡'}：${c.title}`);if(type==='dateIdea'||type==='deepTalk')grantRelationshipChest(type==='dateIdea'?'約會靈感卡完成':'深聊卡完成');saveState();renderAll();toast(type==='dateIdea'?'已標記完成約會卡':'已標記已聊過')}
function saveWish(e){e.preventDefault();const title=val('wishTitle').trim();if(!title)return toast('請輸入願望名稱');const w=wishPayload({title});state.coupleWishPool.unshift(w);state.coupleWishLogs.unshift(withMeta({id:uid('wishLog'),date:todayKey(),wishId:w.id,action:'create',amount:0,note:'手動新增願望',title},'coupleWishLog',state));['wishTitle','wishDescription'].forEach(id=>{const el=$('#'+id);if(el)el.value=''});['wishRequiredIntimacy','wishRequiredChemistry','wishRequiredHeartbeat'].forEach((id,i)=>{const el=$('#'+id);if(el)el.value=['120','80','100'][i]});saveState();renderAll();toast('已新增願望')}
function openInvestWishModal(id){const w=state.coupleWishPool.find(x=>x.id===id&&!x.deletedAt);if(!w)return; if(normalizeWishStatus(w)==='已完成')return toast('已完成願望不可再投入');state.activeWishInvestId=id;const modal=$('#wishInvestModal');const info=$('#wishInvestInfo');const title=$('#wishInvestTitle');const rs=relStats();if(title)title.textContent=`投入關係值：${w.title}`;if(info)info.textContent=`可用親密 ${Number(rs.intimacy||0)}｜可用默契 ${Number(rs.chemistry||0)}｜可用心動 ${Number(rs.heartbeat||0)}；目前：親密 ${w.investedIntimacy||0}/${w.requiredIntimacy||0}、默契 ${w.investedChemistry||0}/${w.requiredChemistry||0}、心動 ${w.investedHeartbeat||0}/${w.requiredHeartbeat||0}`;['wishInvestIntimacy','wishInvestChemistry','wishInvestHeartbeat'].forEach(id=>{const input=$('#'+id);if(input)input.value='0'});modal?.classList.remove('hidden');modal?.setAttribute('aria-hidden','false')}
function closeWishInvestModal(){state.activeWishInvestId='';const modal=$('#wishInvestModal');modal?.classList.add('hidden');modal?.setAttribute('aria-hidden','true')}
function confirmWishInvest(){const id=state.activeWishInvestId;const w=state.coupleWishPool.find(x=>x.id===id&&!x.deletedAt);if(!w)return closeWishInvestModal();const a=Number(val('wishInvestIntimacy')||0),b=Number(val('wishInvestChemistry')||0),c=Number(val('wishInvestHeartbeat')||0);if(a<0||b<0||c<0||a+b+c<=0)return toast('請輸入正確的投入數值');const rs=relStats();if(a>Number(rs.intimacy||0)||b>Number(rs.chemistry||0)||c>Number(rs.heartbeat||0))return toast('不可投入超過目前可用的關係值');if(normalizeWishStatus(w)==='已完成')return toast('已完成願望不可再投入');w.investedIntimacy=Number(w.investedIntimacy||0)+a;w.investedChemistry=Number(w.investedChemistry||0)+b;w.investedHeartbeat=Number(w.investedHeartbeat||0)+c;rs.intimacy=Number(rs.intimacy||0)-a;rs.chemistry=Number(rs.chemistry||0)-b;rs.heartbeat=Number(rs.heartbeat||0)-c;rs.updatedAt=nowIso();w.status=normalizeWishStatus(w);state.coupleWishLogs.unshift(withMeta({id:uid('wishLog'),date:todayKey(),wishId:w.id,action:'invest',intimacy:a,chemistry:b,heartbeat:c,amount:a+b+c,note:`投入親密 ${a}、默契 ${b}、心動 ${c}`,title:w.title},'coupleWishLog',state));closeWishInvestModal();saveState();renderAll();toast(w.status==='已達標'?'願望已達標':'已投入願望')}
function completeWish(id){const w=state.coupleWishPool.find(x=>x.id===id&&!x.deletedAt);if(!w)return;const status=normalizeWishStatus(w);if(status!=='已達標'&&status!=='已完成'){if(!confirm('這個願望尚未達標，仍要標記完成嗎？'))return}if(status==='已完成')return toast('願望已完成');w.status='已完成';w.completedAt=nowIso();state.coupleWishLogs.unshift(withMeta({id:uid('wishLog'),date:todayKey(),wishId:id,action:'complete',amount:0,note:'願望完成',title:w.title},'coupleWishLog',state));state.relationshipLogs.unshift(withMeta({id:uid('rel'),date:todayKey(),action:'completeWish',wishId:id,title:w.title,intimacy:0,chemistry:0,heartbeat:0,couplePoints:0},'relationshipLog',state));grantRelationshipChest('雙人願望完成');saveState();renderAll();toast('願望已完成，已加入關係回顧素材')}
function editWish(id){const w=state.coupleWishPool.find(x=>x.id===id&&!x.deletedAt);if(!w)return;const title=prompt('願望名稱',w.title||'');if(title===null)return;w.title=title.trim()||w.title;w.requiredIntimacy=Number(prompt('所需親密值',w.requiredIntimacy||120)||w.requiredIntimacy||120);w.requiredChemistry=Number(prompt('所需默契值',w.requiredChemistry||80)||w.requiredChemistry||80);w.requiredHeartbeat=Number(prompt('所需心動值',w.requiredHeartbeat||100)||w.requiredHeartbeat||100);w.status=normalizeWishStatus(w);w.updatedAt=nowIso();state.coupleWishLogs.unshift(withMeta({id:uid('wishLog'),date:todayKey(),wishId:id,action:'edit',amount:0,note:'編輯願望',title:w.title},'coupleWishLog',state));saveState();renderAll();toast('已更新願望')}
function copyWish(id){const w=state.coupleWishPool.find(x=>x.id===id&&!x.deletedAt);if(!w)return;const cp=wishPayload({...w,id:uid('wish'),title:`${w.title}（複製）`,investedIntimacy:0,investedChemistry:0,investedHeartbeat:0,status:'想做',completedAt:'',source:'copy'});state.coupleWishPool.unshift(cp);state.coupleWishLogs.unshift(withMeta({id:uid('wishLog'),date:todayKey(),wishId:cp.id,action:'create',amount:0,note:'複製願望',title:cp.title},'coupleWishLog',state));saveState();renderAll();toast('已複製願望')}
function deleteWish(id){const w=state.coupleWishPool.find(x=>x.id===id&&!x.deletedAt);if(!w)return;if(!confirm('確定刪除 / 封存這個願望？已投入的關係值不會自動退回。'))return;w.deletedAt=nowIso();w.status='已刪除';state.coupleWishLogs.unshift(withMeta({id:uid('wishLog'),date:todayKey(),wishId:id,action:'delete',amount:0,note:'刪除 / 封存願望',title:w.title},'coupleWishLog',state));saveState();renderAll();toast('已處理願望')}

function weekKeyOf(date=new Date()){const d=new Date(date);const day=(d.getDay()+6)%7;d.setDate(d.getDate()-day);d.setHours(0,0,0,0);return todayKey(d)}
function convertedThisWeek(){const wk=weekKeyOf();return Math.abs((state.pointsLedger||[]).filter(x=>!x.deletedAt&&x.source==='convertToCouplePoints'&&(x.weekKey===wk||String(x.date||'')>=wk)).reduce((s,x)=>s+Number(x.amount||0),0))}
function convertPersonalToCouplePoints(){const raw=Number(val('personalConvertAmount')||0);if(!raw||raw<=0)return toast('請輸入要轉換的個人點數');const amount=Math.floor(raw/5)*5;if(amount<=0)return toast('轉換點數需至少 5 點，且為 5 的倍數');const used=convertedThisWeek();const remain=Math.max(0,100-used);if(amount>remain)return toast(`本週最多還能轉換 ${remain} 個人點數`);if(amount>currentPoints())return toast('個人點數餘額不足');const gain=Math.floor(amount/5);const wk=weekKeyOf();state.pointsLedger.unshift(withMeta({id:uid('point'),date:todayKey(),weekKey:wk,amount:-amount,source:'convertToCouplePoints',description:`轉換為雙人點數 +${gain}`},'point',state));addCouplePoints(gain,'convertFromPersonal',`由個人點數轉換：${amount} → ${gain}`,wk);saveState();renderAll();toast(`已轉換為 ${gain} 雙人點數`)}
function grantRelationshipChest(source){state.relationshipChests.unshift(withMeta({id:uid('relChest'),name:'關係寶箱',source,status:'available',reward:{intimacy:8,chemistry:6,heartbeat:8,couplePoints:15},rewardLabel:'親密值 +8、默契值 +6、心動值 +8、雙人點數 +15',description:'完成關係互動後獲得的驚喜獎勵。'},'relationshipChest',state));}
function openRelationshipChest(id){const c=state.relationshipChests.find(x=>x.id===id&&!x.deletedAt);if(!c||c.status==='opened')return toast('寶箱已開啟或不存在');const r=c.reward||{};state.relationshipStats.intimacy=Number(state.relationshipStats.intimacy||0)+Number(r.intimacy||0);state.relationshipStats.chemistry=Number(state.relationshipStats.chemistry||0)+Number(r.chemistry||0);state.relationshipStats.heartbeat=Number(state.relationshipStats.heartbeat||state.relationshipStats.companionship||0)+Number((r.heartbeat ?? r.companionship ?? 0));if(r.couplePoints)addCouplePoints(r.couplePoints,'relationshipChest','開啟關係寶箱',id);c.status='opened';c.openedAt=nowIso();state.relationshipChestLogs.unshift(withMeta({id:uid('relChestLog'),date:todayKey(),chestId:id,reward:r},'relationshipChestLog',state));saveState();renderAll();toast('已開啟關係寶箱')}
function relationshipReviewText(scope){
  const s=state.relationshipStats||{};
  const logs=(state.relationshipLogs||[]).filter(l=>scope==='daily'?l.date===todayKey():true).slice(0,12);
  const close=logs.filter(l=>l.action==='completeCloseToday').length;
  const chem=logs.filter(l=>String(l.action||'').startsWith('chemistry')).length;
  const date=logs.filter(l=>l.action==='completeDateIdea').length;
  const talk=logs.filter(l=>l.action==='completeDeepTalk').length;
  const wishes=(state.coupleWishPool||[]).filter(w=>!w.deletedAt);
  const completedWishes=wishes.filter(w=>['已完成','completed'].includes(w.status)).length;
  const warm=logs.find(l=>l.action==='completeCloseToday'||l.action==='completeDeepTalk')?.title||'可以抽一張今日靠近一點，留下今天的小溫暖';
  const interactionCount=logs.filter(l=>['completeCloseToday','chemistrySuccess','chemistryTry','completeDateIdea','completeDeepTalk','completeWish'].includes(l.action)).length;
  const chestCount=(state.relationshipChests||[]).filter(c=>!c.deletedAt&&(scope==='daily'?String(c.date||c.createdAt||'').slice(0,10)===todayKey():true)).length;
  return `${scope==='weekly'?'每週':'今日'}關係回顧
親密值：${s.intimacy||0}｜默契值：${s.chemistry||0}｜心動值：${s.heartbeat||s.companionship||0}
今日靠近一點完成：${close} 次
默契挑戰：${chem} 次
約會靈感卡完成：${date} 次｜深聊卡已聊過：${talk} 次
雙人願望池：${wishes.length} 個願望，已完成 ${completedWishes} 個
本週獲得關係寶箱：${chestCount} 個
來源：完成 ${interactionCount} 次關係互動
本週最溫暖互動：${warm}
本週最值得記住的對話：${logs.map(l=>l.title||l.action).filter(Boolean).slice(0,3).join('、')||'尚未累積'}
下週可以一起做的小事：抽一張約會靈感卡，或把一張深聊卡加入回顧。`;
}
function relationshipPeriodKey(scope){
  if(scope==='weekly'){
    const d=new Date();const start=new Date(d.getFullYear(),0,1);const week=Math.ceil((((d-start)/86400000)+start.getDay()+1)/7);return `${d.getFullYear()}-W${String(week).padStart(2,'0')}`;
  }
  return todayKey();
}
function generateRelationshipReview(scope='daily'){
  const key=relationshipPeriodKey(scope);
  state.relationshipReviews=state.relationshipReviews||[];
  let row=state.relationshipReviews.find(r=>r.scope===scope&&r.periodKey===key&&!r.deletedAt);
  if(!row){row=withMeta({id:uid('relReview'),scope,periodKey:key,latestText:'',snapshots:[]},'relationshipReview',state);state.relationshipReviews.unshift(row)}
  row.latestText=relationshipReviewText(scope);row.generatedAt=nowIso();row.updatedAt=nowIso();
  if(scope==='weekly')grantRelationshipChest('每週關係回顧完成');
  saveState();renderAll();toast(scope==='weekly'?'已產生本週關係回顧':'已產生今日關係回顧');
}
function latestRelationshipReview(){return (state.relationshipReviews||[]).find(r=>!r.deletedAt)||null}
function copyRelationshipReview(id){const row=(state.relationshipReviews||[]).find(r=>r.id===id)||latestRelationshipReview();const text=row?.latestText||relationshipReviewText('daily');if(navigator.clipboard){navigator.clipboard.writeText(text).then(()=>toast('已複製關係回顧')).catch(()=>alert(text));}else alert(text)}
function saveRelationshipReviewSnapshot(id){const row=(state.relationshipReviews||[]).find(r=>r.id===id)||latestRelationshipReview();if(!row)return toast('請先產生關係回顧');state.relationshipReviewSnapshots=state.relationshipReviewSnapshots||[];state.relationshipReviewSnapshots.unshift(withMeta({id:uid('relSnap'),reviewId:row.id,snapshotName:`關係回顧快照 ${new Date().toLocaleString('zh-TW')}`,text:row.latestText||'',scope:row.scope,periodKey:row.periodKey},'relationshipReviewSnapshot',state));saveState();renderAll();toast('已另存關係回顧快照')}
function saveLatestRelationshipSnapshot(){saveRelationshipReviewSnapshot(latestRelationshipReview()?.id)}
function mapNodeById(id){return (state.mapNodes||[]).find(n=>n.id===id&&!n.deletedAt)}
function mapNodesFor(mode){return (state.mapNodes||[]).filter(n=>n.mode===mode&&!n.deletedAt).sort((a,b)=>Number(a.requiredSteps||0)-Number(b.requiredSteps||0))}
function isNodeUnlocked(node){const p=mapProgressFor(node.mode);return (p.unlockedNodeIds||[]).includes(node.id)||Number(node.requiredSteps||0)<=Number(p.currentSteps||0)}
function isCurrentMapNode(node){const p=mapProgressFor(node.mode);return p.currentNodeId===node.id}
function hasExploredMapObject(obj,node){const today=todayKey();return (state.mapExploreLogs||[]).some(l=>!l.deletedAt&&l.objectId===obj.id&&l.nodeId===node.id&&(isCurrentMapNode(node)?l.date===today:true))}
function adventureLog(payload={}){const mode=payload.mode==='couple'?'couple':'solo';const p=mapProgressFor(mode);const row=withMeta({id:payload.id||uid('adv'),date:payload.date||todayKey(),userId:state.currentUserId||'me',roomId:state.firebase?.roomId||state.roomId||'',sourceType:payload.sourceType||'mapExplore',sourceLogId:payload.sourceLogId||payload.objectId||'',taskId:payload.taskId||'',mapType:mode==='couple'?'couple':'single',mode,steps:Number(payload.steps||0),fromStep:Number((payload.fromStep ?? p.currentSteps) || 0),toStep:Number((payload.toStep ?? p.currentSteps) || 0),fromNodeId:payload.fromNodeId||payload.nodeId||p.currentNodeId,toNodeId:payload.toNodeId||payload.nodeId||p.currentNodeId,reason:payload.title||payload.description||'冒險紀錄',description:payload.description||payload.title||'冒險紀錄',createdAt:nowIso(),updatedAt:nowIso(),deletedAt:null,version:state.version||'14C',revertedAt:null,revertedBy:'',revertReason:'',...payload},'adventureLog',state);state.adventureLogs.unshift(row);state.adventure.logs=state.adventureLogs;return row}
function mapQuestConditionReady(q){return true}
function findMapSideQuest(id){for(const node of state.mapNodes||[]){for(const q of node.sideQuests||[]){if(q.id===id)return {node,q}}}const q=(state.mapSideQuests||[]).find(x=>x.id===id&&!x.deletedAt);const node=q?mapNodeById(q.nodeId)||mapNodesFor(q.mode||'solo')[0]:null;return q&&node?{node,q}:null}
function claimMapSideQuest(id){const found=findMapSideQuest(id);if(!found)return toast('找不到地圖支線');const {node,q}=found;if(!isNodeUnlocked(node))return toast('該地區尚未解鎖');let prog=(state.mapSideQuestProgress||[]).find(p=>(p.sideQuestId===q.id||p.questId===q.id)&&!p.deletedAt);if(prog?.status==='completed')return toast('這個地圖支線已完成');if(!prog){prog=withMeta({id:uid('mapSideProg'),sideQuestId:q.id,questId:q.id,nodeId:node.id,mode:node.mode,status:'active',progress:0,target:1},'mapSideQuestProgress',state);state.mapSideQuestProgress.unshift(prog)}prog.status='completed';prog.completed=true;prog.completedAt=nowIso();prog.updatedAt=nowIso();const r=q.reward||{};if(r.points)addPoints(Number(r.points)||0,'mapSideQuest',`完成地圖支線：${q.title}`,q.id);if(r.exp)grantExp(Number(r.exp)||0,'mapSideQuest',`完成地圖支線：${q.title}`,q.id);if(r.item)grantItem(r.item,Number(r.qty||1),'mapSideQuest');if(r.bossDamage)applyBossDamage(Number(r.bossDamage)||0,'adventure',`地圖支線：${q.title}`,{questId:q.id,nodeId:node.id});addMapSteps(node.mode,Number(q.mapSteps||r.mapSteps||3),'mapSideQuest',`地圖支線完成：${q.title}`,{sourceType:'mapSideQuest',sourceLogId:prog.id,questId:q.id,taskId:q.id,nodeId:node.id});saveState();renderAll();openMapModal(node.id,node.mode);toast('已完成地圖支線並推進冒險')}
function goToMapSideQuest(id){const found=findMapSideQuest(id);if(found)openMapModal(found.node.id,found.node.mode);else toast('找不到地圖支線')}
function exploreMapObject(objectId,nodeId){const obj=(state.mapExploreObjects||[]).find(o=>o.id===objectId);if(!obj)return toast('找不到探索物件');const node=mapNodeById(nodeId||obj.nodeId);if(!node||!isNodeUnlocked(node))return toast('該地區尚未解鎖');if(hasExploredMapObject(obj,node))return toast(isCurrentMapNode(node)?'今日已探索過，明天可再次探索':'已探索過');const r=obj.reward||{};let desc=`探索：${obj.name}`;if(r.item){grantItem(r.item,Number(r.qty||1),'mapExplore');state.mapInventoryLogs.unshift(withMeta({id:uid('mapInvLog'),date:todayKey(),nodeId:node.id,objectId:obj.id,itemName:r.item,quantity:Number(r.qty||1),source:'mapExplore'},'mapInventoryLog',state));const existing=state.mapInventory.find(i=>i.name===r.item);if(existing){existing.quantity=Number(existing.quantity||0)+Number(r.qty||1);existing.updatedAt=nowIso()}else state.mapInventory.push(withMeta({id:uid('mapInv'),name:r.item,quantity:Number(r.qty||1),source:'mapExplore',usageType:'mapOrBoss',description:'由地圖探索取得，可在地圖背包或錢包使用。'},'mapInventory',state));desc+=`，獲得 ${r.item} x${r.qty||1}`;}if(r.hiddenQuestTitle){const h=withMeta({id:`hidden_${objectId}`,nodeId:node.id,mode:node.mode,title:r.hiddenQuestTitle,description:`由探索 ${obj.name} 解鎖的地圖隱藏支線。`,condition:{type:'bossDamage',target:30,label:'對 Boss 造成 30 傷害'},status:'active',reward:{points:20,exp:20,bossDamage:30,item:'星光碎片'}},'mapHiddenQuest',state);upsertById('mapHiddenQuests',h,'mapHiddenQuest');if(!state.mapQuestProgress.some(p=>p.hiddenQuestId===h.id&&!p.deletedAt))state.mapQuestProgress.push(withMeta({id:`progress_${h.id}`,hiddenQuestId:h.id,status:'active',progress:0,target:1},'mapQuestProgress',state));desc+=`，解鎖地圖隱藏支線：${r.hiddenQuestTitle}`;}if(r.story){desc+=`：${r.story}`}if(r.ability){state.abilityEffects.unshift(withMeta({id:uid('ability'),date:todayKey(),nodeId:node.id,objectId:obj.id,effect:r.ability,status:'active'},'abilityEffect',state));state.activeItemEffects.unshift(withMeta({id:uid('activeEffect'),date:todayKey(),nodeId:node.id,objectId:obj.id,effect:r.ability,target:'map',status:'active'},'activeItemEffect',state));desc+=`，獲得能力：${r.ability}`}const log=withMeta({id:uid('mapExplore'),date:todayKey(),mode:node.mode,nodeId:node.id,placeName:node.name,objectId:obj.id,objectName:obj.name,title:desc,reward:r,isCurrentNode:isCurrentMapNode(node),resetRule:isCurrentMapNode(node)?'dailyCurrentNode':'oncePassedNode'},'mapExploreLog',state);state.mapExploreLogs.unshift(log);if(isCurrentMapNode(node))state.mapExploreDailyLogs.unshift(withMeta({id:uid('mapDailyExplore'),date:todayKey(),mode:node.mode,nodeId:node.id,objectId:obj.id,objectName:obj.name},'mapExploreDailyLog',state));adventureLog({id:uid('adv'),date:todayKey(),mode:node.mode,nodeId:node.id,placeName:node.name,title:desc,objectId:obj.id,sourceType:'mapExplore',sourceLogId:log.id});addGameLog('mapExplore',desc,{nodeId:node.id,objectId:obj.id,reward:r});saveState();renderAll();openMapModal(node.id,node.mode);toast(desc)}
function completeSidequest(key){const [mode,index,side]=key.split(':');const nodes=(state.mapNodes||[]).filter(n=>n.mode===mode).sort((a,b)=>a.requiredSteps-b.requiredSteps);const node=nodes[Number(index)];const q=node?.sideQuests?.[Number(side)];if(q)return claimMapSideQuest(q.id);toast('請從地點視窗領取地圖支線')}
function exploreObject(id){return toast('請在已解鎖地點的視窗中探索一次性物件')}
function exploreMap(mode){const p=mapProgressFor(mode);const node=mapNodeById(p.currentNodeId)||((state.mapNodes||[]).filter(n=>n.mode===mode).sort((a,b)=>a.requiredSteps-b.requiredSteps)[0]);if(node)openMapModal(node.id,mode)}
function generateMonthlyReportAction(){const row=generateMonthlyReport();saveState();renderAll();toast('已產生每月人生報告');return row}
function copyMonthlyReport(){const row=state.monthlyReports[0]||generateMonthlyReport();const text=row.text||'';if(navigator.clipboard){navigator.clipboard.writeText(text).then(()=>toast('已複製月報')).catch(()=>alert(text));}else alert(text)}
async function authToggle(){try{if(state.firebase.user){await signOutGoogle();toast('已登出')}else{const ok=await signInWithGoogle();toast(ok?'已登入並自動同步':'Firebase 尚未設定或登入失敗')}}catch(e){console.warn(e);toast('Firebase 尚未設定或登入失敗')}renderAll()}
async function forceLocalToCloud(){if(!confirm('確定要用本機資料覆蓋雲端？請先匯出 JSON 備份。'))return;const ok=await pushUserToCloud();toast(ok?'已用本機資料覆蓋雲端':'覆蓋雲端失敗或尚未登入');renderAll()}
async function forceCloudToLocal(){if(!confirm('確定要用雲端資料覆蓋本機？請先匯出 JSON 備份。'))return;const ok=await pullUserFromCloud();toast(ok?'已用雲端資料覆蓋本機':'讀取雲端失敗或尚未登入');renderAll()}
async function syncNow(){const ok=await syncAllNow();renderAll();toast(ok?'已同步':'尚未完成 Firebase 設定或登入')}function restoreBackupAction(){if(!confirm('確定還原同步前備份？目前本機資料會被備份內容取代，建議先匯出 JSON。'))return;const ok=restorePreSyncBackup();renderAll();toast(ok?'已還原同步前備份':'沒有可還原的同步前備份')}function exportJson(){const blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`habit-backup-${todayKey()}.json`;a.click();URL.revokeObjectURL(url)}function createPreImportBackup(){try{const backup={createdAt:nowIso(),state:JSON.parse(JSON.stringify(state))};localStorage.setItem(PRE_IMPORT_BACKUP_KEY,JSON.stringify(backup));state.syncMeta=state.syncMeta||{};state.syncMeta.preImportBackupAt=backup.createdAt;state.syncMeta.hasPreImportBackup=true}catch(e){console.warn(e)}}function restorePreImportBackup(){try{const raw=localStorage.getItem(PRE_IMPORT_BACKUP_KEY);if(!raw)return toast('目前沒有可還原的匯入前備份');const parsed=JSON.parse(raw);if(!parsed?.state)return toast('匯入前備份格式不完整');if(!confirm('確定還原匯入前備份？目前資料會被備份內容取代。'))return;replaceState(migrate(parsed.state),{touch:true,emit:true,source:'restorePreImportBackup'});renderAll();toast('已還原匯入前備份')}catch(e){console.warn(e);toast('還原匯入前備份失敗')}}function importJson(file){if(!file)return;const reader=new FileReader();reader.onload=()=>{try{createPreImportBackup();replaceState(migrate(JSON.parse(reader.result)),{touch:true,emit:true,source:'jsonImport'});renderAll();toast('匯入完成，已建立匯入前備份並排程同步')}catch(e){console.warn(e);toast('JSON 格式錯誤，已保留原資料')}};reader.readAsText(file)}function resetAll(){if(!confirm('確定清空本機全部資料？請確認已匯出 JSON 備份。'))return;if(!confirm('再次確認：清空後目前瀏覽器資料會消失，確定繼續？'))return;resetState();location.reload()}async function clearCloudData(){if(!confirm('確定清空雲端資料？請先匯出 JSON 備份。'))return;if(!confirm('再次確認：將以清空後的本機資料覆蓋雲端。確定繼續？'))return;resetState();const ok=await pushUserToCloud();toast(ok?'已清空並覆蓋雲端資料':'清空雲端失敗，可能尚未登入或 Firebase 未設定');location.reload()}


function syncHabitRewardRuleTable(habitId,rules=[]){
  state.habitRewardRules=(state.habitRewardRules||[]).filter(r=>r.habitId!==habitId);
  for(const r of rules){state.habitRewardRules.push(withMeta({id:`${habitId}_${r.rewardRuleId}`,habitId,rewardRuleId:r.rewardRuleId,rule:r},'habitRewardRule',state))}
}
function claimHabitReward(key){const [habitId,ruleId]=String(key).split(':');const h=state.habits.find(x=>x.id===habitId);const r=h?.rewardRules?.find(x=>x.rewardRuleId===ruleId);if(!h||!r)return toast('找不到獎勵規則');r.claimedHistory=r.claimedHistory||[];if(r.claimedHistory.some(x=>x.claimedAt)&&!r.repeatable)return toast('此獎勵已領取');for(const it of r.rewardItems||[]){const type=it.type||it.rewardType;const value=it.value??it.amount??it.name;if(type==='points')addPoints(Number(value)||0,'habitReward',`${h.title} 長期獎勵`,ruleId);else if(type==='exp')grantExp(Number(value)||0,'habitReward',`${h.title} 長期獎勵`,ruleId);else if(type==='chest'||type==='item')grantItem(String(value),Number(it.qty||1),'habitReward');else if(type==='bossDamage')applyBossDamage(Number(value)||0,'habitReward',`${h.title} 長期獎勵`,ruleId);else if(type==='mapSteps')addMapSteps('solo',Number(value)||0,'habitReward',`${h.title} 長期獎勵推進地圖`,{sourceType:'habitReward',sourceLogId:ruleId,taskId:h.id});else if(type==='couplePoints')addCouplePoints(Number(value)||0,'habitReward',`${h.title} 長期獎勵`,ruleId);else if(type==='badge'){state.achievements.unshift(withMeta({id:uid('ach'),name:value==='auto'?autoBadgeName(h,r):String(value),description:`由 ${h.title} 的長期獎勵解鎖`,unlocked:true,unlockedAt:nowIso(),progress:1,target:1},'achievement',state));}}
  r.claimedHistory.push({claimedAt:nowIso(),ruleId,habitId});state.habitRewardLogs.unshift(withMeta({id:uid('habitRewardLog'),habitId,rewardRuleId:ruleId,rewardItems:r.rewardItems,claimedAt:nowIso()},'habitRewardLog',state));saveState();renderAll();toast('已領取長期獎勵')}
function createQuestPrompt(){
  const title=prompt('任務線名稱，例如：14 天早睡挑戰','我的 14 天主線挑戰');if(!title)return;
  const category=prompt('分類，例如：健康 / 學習 / 自律 / 關係','健康')||'健康';
  const durationDays=Number(prompt('期間天數','14')||14);
  const target=Number(prompt('目標完成次數','10')||10);
  const linkedHabitId=prompt('對應主線任務 ID（可留空，之後編輯）','')||'';
  const rewardPoints=Number(prompt('完成獎勵點數','120')||120);
  const rewardExp=Number(prompt('完成 EXP','140')||140);
  const rewardItem=prompt('完成寶箱 / 道具','金寶箱')||'';
  const badge=prompt('完成徽章名稱',`${title}徽章`)||`${title}徽章`;
  const q=addCustomQuest(title,target,category);
  q.durationDays=durationDays;q.linkedHabitId=linkedHabitId;q.linkedCategory=category;q.reward={points:rewardPoints,exp:rewardExp,item:rewardItem,badge};q.mapReward={steps:10};q.bossItemReward='';q.enabled=true;q.status='not_started';q.updatedAt=nowIso();
  saveState();renderAll();toast(`已新增任務線：${q.title}`)
}
function editQuestLine(id){
  const q=state.quests.find(x=>x.id===id&&!x.deletedAt);if(!q)return;
  const title=prompt('任務線名稱',q.title||'');if(title===null)return;
  const category=prompt('分類',q.category||'健康');if(category===null)return;
  const durationDays=Number(prompt('期間天數',q.durationDays||14)||q.durationDays||14);
  const target=Number(prompt('目標次數',q.target||1)||q.target||1);
  const linkedHabitId=prompt('對應主線任務 ID',q.linkedHabitId||'');if(linkedHabitId===null)return;
  const rewardPoints=Number(prompt('獎勵點數',q.reward?.points||80)||q.reward?.points||80);
  const rewardExp=Number(prompt('EXP',q.reward?.exp||80)||q.reward?.exp||80);
  const rewardItem=prompt('寶箱 / 道具',q.reward?.item||'木寶箱');if(rewardItem===null)return;
  const badge=prompt('徽章',q.reward?.badge||`${title}徽章`);if(badge===null)return;
  q.title=title;q.category=category;q.linkedCategory=category;q.durationDays=durationDays;q.target=target;q.linkedHabitId=linkedHabitId;q.reward={...(q.reward||{}),points:rewardPoints,exp:rewardExp,item:rewardItem,badge};q.enabled=true;q.updatedAt=nowIso();
  const p=state.questProgress.find(x=>x.questId===id&&!x.deletedAt);if(p){p.title=title;p.target=target;p.updatedAt=nowIso();}
  saveState();renderAll();toast('已更新任務線');
}


function convertLegacyReward(id){
  const legacy=(state.legacyRewardPlans||[]).find(x=>x.id===id&&!x.deletedAt);
  if(!legacy)return toast('找不到舊任務線資料');
  if(!state.habits.length)return toast('請先新增一個習慣，再轉成習慣獎勵');
  const habitName=prompt('要轉入哪個習慣？請輸入習慣名稱',state.habits[0]?.title||'');
  if(habitName===null)return;
  const h=state.habits.find(x=>x.title===habitName)||state.habits[0];
  h.rewardRules=h.rewardRules||[];
  const rule=normalizeRewardRules([{rewardTriggerType:'periodCount',conditionValue:Number(legacy.target||legacy.conditionValue||7)||7,conditionPeriod:'customDays',rewardItems:[{type:'points',value:Number(legacy.reward?.points||legacy.points||80)||80},{type:'badge',value:legacy.reward?.badge||`${legacy.title||'舊任務線'}徽章`}],detailNote:`由舊任務線「${legacy.title||'未命名'}」轉入`,repeatable:false,enabled:true}],h)[0];
  h.rewardRules.push(rule);
  legacy.convertedToHabitId=h.id;legacy.convertedAt=nowIso();
  syncHabitRewardRuleTable(h.id,h.rewardRules);
  saveState();renderAll();toast('已轉成習慣獎勵規則');
}

function generateWeeklyReviewAction(){const row=generateWeeklyReview();saveState();renderAll();toast('已產生本週戰報');return row}
function copyWeeklyReview(){const row=state.weeklyReviews[0]||generateWeeklyReview();const text=row.text||'';if(navigator.clipboard){navigator.clipboard.writeText(text).then(()=>toast('已複製戰報')).catch(()=>alert(text));}else alert(text)}
function tableData(table){
  if(table==='chemistryChallengeSessions')return (state.chemistryChallengeSessions||[]).map(r=>({...r,optionA:r.options?.[0]||'',optionB:r.options?.[1]||'',optionC:r.options?.[2]||'',optionD:r.options?.[3]||''}));
  if(table==='levelData')return [state.levelData];
  if(table==='coupleStats')return [state.coupleStats];
  if(table==='settings')return [state.settings];
  if(table==='syncMeta')return [state.syncMeta];
  if(table==='adventureLogs')return state.adventureLogs||state.adventure.logs||[];
  if(table==='stats'||table==='importedStats')return table==='stats'?buildStatsRows():(state.importedStats||[]);
  if(table==='logs')return Object.values(state.logs||{});
  if(table==='items')return state.gameItems||[];
  if(table==='dailyMissions')return [state.missions.daily];
  if(table==='flexMissions')return [state.missions.flex];
  return Array.isArray(state[table])?state[table]:[];
}
function csvEscape(v){if(typeof v==='object'&&v!==null)v=JSON.stringify(v);v=String(v??'');return /[",\n]/.test(v)?`"${v.replace(/"/g,'""')}"`:v}
function toCsv(rows){rows=Array.isArray(rows)?rows:[];const keys=[...new Set(rows.flatMap(r=>Object.keys(r||{})))];return [keys.join(','),...rows.map(r=>keys.map(k=>csvEscape(r?.[k])).join(','))].join('\n')}
function exportCsv(table){const rows=tableData(table);const blob=new Blob(['\ufeff'+toCsv(rows)],{type:'text/csv;charset=utf-8'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`${table}-${todayKey()}.csv`;a.click();URL.revokeObjectURL(url)}
function parseCsv(text){text=String(text||'').replace(/^\ufeff/,'');const rows=[];let row=[],cell='',q=false;for(let i=0;i<text.length;i++){const c=text[i],n=text[i+1];if(q&&c==='"'&&n==='"'){cell+='"';i++;continue}if(c==='"'){q=!q;continue}if(!q&&c===','){row.push(cell);cell='';continue}if(!q&&(c==='\n'||c==='\r')){if(c==='\r'&&n==='\n')i++;row.push(cell);if(row.some(x=>x!==''))rows.push(row);row=[];cell='';continue}cell+=c}row.push(cell);if(row.some(x=>x!==''))rows.push(row);const headers=rows.shift()||[];return rows.map(r=>Object.fromEntries(headers.map((h,i)=>[h,parseCell(r[i])]))) }
function parseCell(v){if(v==null)return '';const s=String(v);if((s.startsWith('{')&&s.endsWith('}'))||(s.startsWith('[')&&s.endsWith(']'))){try{return JSON.parse(s)}catch{}}if(/^-?\d+(\.\d+)?$/.test(s))return Number(s);return s}
function importCsv(table,file){const reader=new FileReader();reader.onload=()=>{try{createPreImportBackup();const rows=parseCsv(reader.result).map(r=>withMeta(r,table,state));
    if(table==='levelData')state.levelData=withMeta(rows[0]||{},'levelData',state);
    else if(table==='coupleStats')state.coupleStats=withMeta(rows[0]||{},'coupleStats',state);
    else if(table==='settings')state.settings=withMeta(rows[0]||{},'settings',state);
    else if(table==='syncMeta')state.syncMeta=withMeta(rows[0]||{},'syncMeta',state);
    else if(table==='adventureLogs'){state.adventureLogs=rows;state.adventure.logs=rows;} 
    else if(table==='logs'||table==='habitLogs'){state.habitLogs=rows;state.logs=Object.fromEntries(rows.filter(r=>!r.deletedAt).map(r=>[`${r.date}:${r.habitId||r.taskId}`,r]));}
    else if(table==='chemistryChallengeSessions'){state.chemistryChallengeSessions=rows.map(r=>withMeta({...r,options:Array.isArray(r.options)?r.options:[r.optionA,r.optionB,r.optionC,r.optionD].filter(Boolean)},'chemistryChallengeSession',state));}
    else if(table==='items'||table==='gameItems'){state.gameItems=rows;state.items=state.gameItems;}
    else if(table==='dailyMissions')state.missions.daily=rows[0]||state.missions.daily;
    else if(table==='flexMissions')state.missions.flex=rows[0]||state.missions.flex;
    else if(table==='stats'||table==='importedStats')state.importedStats=rows;
    else if(Array.isArray(state[table]))state[table]=rows;
    replaceState(migrate(state),{touch:true,emit:true,source:'csvImport'});renderAll();toast('CSV 匯入完成，已排程同步');
  }catch(e){console.warn(e);toast('CSV 匯入失敗，已保留原資料')}};reader.readAsText(file,'utf-8')}
function buildStatsRows(){const rows=[];rows.push({type:'summary',name:'完成紀錄',value:Object.keys(state.logs).length});rows.push({type:'summary',name:'目前點數',value:currentPoints()});rows.push({type:'summary',name:'個人格數',value:state.adventure.soloStep});rows.push({type:'summary',name:'共同格數',value:state.adventure.coupleStep});for(const l of Object.values(state.logs)){rows.push({type:'log',date:l.date,title:l.title,points:l.points,periodKey:l.periodKey||'',periodLabel:l.periodLabel||''})}return rows}

