function redeemShared(id){const r=state.sharedRewards.find(x=>x.id===id&&!x.deletedAt)||defaultSharedRewards.find(x=>x.id===id);if(!r)return toast('獎勵不存在');if(currentCouplePoints()<Number(r.cost||0))return toast('雙人點數不足');state.sharedRewardRedemptions.unshift(withMeta({id:uid('sharedRedeem'),rewardId:r.id,name:r.name,cost:Number(r.cost||0),date:todayKey(),used:false,usedAt:'',note:'',source:r.source==='builtin'||String(r.id).startsWith('sr_builtin_')?'builtin':'custom'},'sharedRewardRedemption',state));addCouplePoints(-Number(r.cost||0),'sharedReward',`兌換雙人獎勵：${r.name}`,r.id);saveState();renderAll();toast('已兌換雙人獎勵')}
