function requestSharedChange(progressId,requestType='swap'){const p=state.sharedTaskProgress.find(x=>x.id===progressId&&!x.deletedAt);if(!p)return;state.sharedTaskChangeRequests=state.sharedTaskChangeRequests||[];state.sharedTaskChangeRequests.unshift(withMeta({id:uid('sharedReq'),sharedTaskProgressId:p.id,questId:p.questId,requestType,status:'pending',reason:requestType==='swap'?'提出更換共同任務':'提出跳過共同任務'},'sharedTaskChangeRequest',state));saveState();renderAll();toast('已提出，需對方同意')}
function respondSharedChange(id,approve){const r=(state.sharedTaskChangeRequests||[]).find(x=>x.id===id&&!x.deletedAt);if(!r)return;r.status=approve?'approved':'rejected';r.respondedAt=nowIso();if(approve){const p=state.sharedTaskProgress.find(x=>x.id===r.sharedTaskProgressId);if(p){if(r.requestType==='skip'){p.status='skipped';p.settledAt=nowIso()}else{p.status='replaced';p.replacedAt=nowIso();p.swapHistory=[...(p.swapHistory||[]),{requestId:r.id,approvedAt:nowIso(),fromQuestId:p.questId}];const pool=(state.sharedTasks||state.sharedQuests||[]).filter(q=>!q.deletedAt);const activeIds=new Set((state.sharedTaskProgress||[]).filter(x=>x.status==='active'&&!x.deletedAt).map(x=>x.questId));let q=pool.find(x=>x.id!==p.questId&&!activeIds.has(x.id))||pool.find(x=>x.id!==p.questId)||pool.find(x=>x.id===p.questId);if(q){const total=Number(q.totalDays||q.periodDays||7);const start=todayKey();const d=new Date(start+'T00:00:00');d.setDate(d.getDate()+total-1);const end=todayKey(d);state.sharedTaskProgress.unshift(withMeta({id:uid('sharedProgress'),questId:q.id,title:q.title,scope:q.scope,status:'active',progress:0,target:q.target||1,myProgress:0,partnerProgress:0,periodKey:`${q.id}_${start}`,periodStart:start,periodEnd:end,totalDays:total,dayIndex:1,completedCount:0,swapHistory:[],settledAt:null,replacedAt:null,completedAt:''},'sharedTaskProgress',state));}}}}saveState();renderAll();toast(approve?'已同意共同任務變更':'已拒絕共同任務變更')}


function applyCoupleChallengeEffects(c,sourceLogId='',reason='complete'){
  if(!c||c.effectAppliedAt)return;
  const r=c.reward||{};
  const challengeId=c.id;
  const logId=sourceLogId||challengeId;
  if(Number(r.couplePoints||0))addCouplePoints(Number(r.couplePoints||0),'coupleChallenge',`完成雙人挑戰：${c.title}`,challengeId);
  if(r.item)grantItem(r.item,1,'coupleChallenge');
  const intimacy=Number(r.intimacy||0),chemistry=Number(r.chemistry||0),heartbeat=Number(r.heartbeat||0);
  if(intimacy||chemistry||heartbeat){
    state.relationshipStats=state.relationshipStats||{id:'relationship_stats_main',intimacy:0,chemistry:0,heartbeat:0,companionship:0};
    state.relationshipStats.intimacy=Number(state.relationshipStats.intimacy||0)+intimacy;
    state.relationshipStats.chemistry=Number(state.relationshipStats.chemistry||0)+chemistry;
    state.relationshipStats.heartbeat=Number(state.relationshipStats.heartbeat ?? state.relationshipStats.companionship ?? 0)+heartbeat;
    state.relationshipStats.companionship=Number(state.relationshipStats.companionship||0)+heartbeat;
    state.relationshipStats.updatedAt=nowIso();
    state.relationshipLogs.unshift(withMeta({id:uid('rel'),date:todayKey(),source:'coupleChallenge',sourceLogId:logId,challengeId,title:`雙人挑戰完成：${c.title}`,description:c.description||'',intimacy,chemistry,heartbeat,companionship:heartbeat},'relationshipLog',state));
  }
  if(c.countForBoss!==false&&Number(r.bossDamage||0))applyBossDamage(Number(r.bossDamage||0),'coupleChallenge',`雙人挑戰完成：${c.title}`,{challengeId,sourceLogId:logId});
  if(c.countForShared!==false){
    const active=(state.sharedTaskProgress||[]).filter(p=>p.status==='active'&&!p.deletedAt);
    active.forEach(p=>{p.progress=Math.min(Number(p.target||1),Number(p.progress||0)+1);p.myProgress=Number(p.myProgress||0)+1;p.updatedAt=nowIso();if(p.progress>=Number(p.target||1)&&!p.completedAt){p.status='completed';p.completedAt=nowIso();}});
  }
  addMapSteps('couple',Number(r.mapSteps||c.mapSteps||4),'coupleChallenge',`雙人挑戰完成推進地圖：${c.title}`,{sourceType:'coupleChallenge',sourceLogId:logId,challengeId,taskId:challengeId});
  if(c.countForReport!==false){state.coupleBattleReports.unshift(withMeta({id:uid('coupleReport'),scope:'challenge',date:todayKey(),challengeId,sourceLogId:logId,text:`完成雙人挑戰「${c.title}」：雙人點數 +${Number(r.couplePoints||0)}，Boss 傷害 +${Number(r.bossDamage||0)}，親密值 +${intimacy}，默契值 +${chemistry}，心動值 +${heartbeat}`},'coupleBattleReport',state));}
  addGameLog('coupleChallengeComplete',`完成雙人挑戰：${c.title}`,{challengeId,sourceLogId:logId,reward:r,reason});
  c.effectAppliedAt=nowIso();
}

function settleChallenge(id){const c=state.coupleChallenges.find(x=>x.id===id);if(!c)return;const wasCompleted=c.status==='completed';c.status='completed';c.completedAt=c.completedAt||nowIso();if(!wasCompleted||!c.effectAppliedAt)applyCoupleChallengeEffects(c,id,'settle');saveState();renderAll();toast('已結算雙人挑戰')}
function startChallenge(id){const c=state.coupleChallenges.find(x=>x.id===id);if(!c)return;c.status='active';c.updatedAt=nowIso();saveState();renderAll();toast('已開始雙人挑戰')}
function abandonChallenge(id){const c=state.coupleChallenges.find(x=>x.id===id);if(!c)return;c.status='abandoned';c.updatedAt=nowIso();saveState();renderAll();toast('已放棄挑戰')}
function copyChallenge(id){const c=state.coupleChallenges.find(x=>x.id===id);if(!c)return;const cp=withMeta({...c,id:uid('challenge'),title:`${c.title}（複製）`,source:'user',status:'active',progress:0,myProgress:0,partnerProgress:0},'coupleChallenge',state);state.coupleChallenges.unshift(cp);saveState();renderAll();toast('已複製挑戰')}
function deleteChallenge(id){const c=state.coupleChallenges.find(x=>x.id===id);if(!c)return;c.deletedAt=nowIso();c.status='deleted';saveState();renderAll();toast('已刪除挑戰')}
function freqValueToRule(label,count=1){const map={'每日':'daily','每週':'weekly','每 10 天':'tenDays','每雙週':'biweekly','每月':'monthly','每季':'quarterly','每年':'yearly'};return normalizeRule({type:map[label]||'weekly',mode:map[label]||'weekly',count:Number(count)||1})}
