function completeChallengeProgress(id){const c=state.coupleChallenges.find(x=>x.id===id&&!x.deletedAt);if(!c)return;if(c.status==='completed')return toast('這個挑戰已完成');c.status=c.status==='not_started'?'active':(c.status||'active');c.progress=Math.min(Number(c.target||1),Number(c.progress||0)+1);c.myProgress=Number(c.myProgress||0)+1;c.updatedAt=nowIso();const prog=withMeta({id:uid('ccProg'),challengeId:id,date:todayKey(),amount:1,type:'complete',status:'recorded'},'coupleChallengeProgress',state);state.coupleChallengeProgress.unshift(prog);addMapSteps('couple',Number(c.mapSteps||2),'coupleChallenge',`雙人挑戰完成進度推進地圖：${c.title}`,{sourceType:'coupleChallenge',sourceLogId:prog.id,challengeId:id,taskId:id});if(c.progress>=Number(c.target||1))settleChallenge(id);else{saveState();renderAll();toast('已記錄雙人挑戰進度')}}
